module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 라이선스: 대한성서공회 공식 저작권 FAQ에 따라 저작재산권 보호기간 50년 경과로 저작권료 지급 없이 사용 가능 공공저작물 (개역개정판은 해당 없음). 데이터 출처: scrollmapper/bible_databases (GitHub, 2025-languages branch, sources/ko/KorRV/KorRV.json, License: Public Domain)."},"kids":{"label":"쉬운말","note":"쉬운말 번역 준비 중입니다."}},"chapters":[{"chapter":1,"title":"복음과 십자가의 지혜","verses":{"krv":[{"n":1,"t":"하나님의 뜻을 따라 그리스도 예수의 사도로 부르심을 입은 바울과 및 형제 소스데네는"},{"n":2,"t":"고린도에 있는 하나님의 교회 곧 그리스도 예수 안에서 거룩하여지고 성도라 부르심을 입은 자들과 또 각처에서 우리의 주 곧 저희와 우리의 주 되신 예수 그리스도의 이름을 부르는 모든 자들에게"},{"n":3,"t":"하나님 우리 아버지와 주 예수 그리스도로 좇아 은혜와 평강이 있기를 원하노라"},{"n":4,"t":"그리스도 예수 안에서 너희에게 주신 하나님의 은혜를 인하여 내가 너희를 위하여 항상 하나님께 감사하노니"},{"n":5,"t":"이는 너희가 그의 안에서 모든 일 곧 모든 구변과 모든 지식에 풍족하므로"},{"n":6,"t":"그리스도의 증거가 너희 중에 견고케 되어"},{"n":7,"t":"너희가 모든 은사에 부족함이 없이 우리 주 예수 그리스도의 나타나심을 기다림이라"},{"n":8,"t":"주께서 너희를 우리 주 예수 그리스도의 날에 책망할 것이 없는 자로 끝까지 견고케 하시리라"},{"n":9,"t":"너희를 불러 그의 아들 예수 그리스도 우리 주로 더불어 교제케 하시는 하나님은 미쁘시도다"},{"n":10,"t":"형제들아 내가 우리 주 예수 그리스도의 이름으로 너희를 권하노니 다 같은 말을 하고 너희 가운데 분쟁이 없이 같은 마음과 같은 뜻으로 온전히 합하라"},{"n":11,"t":"내 형제들아 글로에의 집 편으로서 너희에게 대한 말이 내게 들리니 곧 너희 가운데 분쟁이 있다는 것이라"},{"n":12,"t":"이는 다름아니라 너희가 각각 이르되 나는 바울에게, 나는 아볼로에게, 나는 게바에게, 나는 그리스도에게 속한 자라 하는 것이니"},{"n":13,"t":"그리스도께서 어찌 나뉘었느뇨 바울이 너희를 위하여 십자가에 못 박혔으며 바울의 이름으로 너희가 침례를 받았느뇨"},{"n":14,"t":"그리스보와 가이오 외에는 너희 중 아무에게도 내가 침례를 주지 아니한 것을 감사하노니"},{"n":15,"t":"이는 아무도 나의 이름으로 침례를 받았다 말하지 못하게 하려함이라"},{"n":16,"t":"내가 또한 스데바나 집 사람에게 침례를 주었고 그 외에는 다른 아무에게 침례를 주었는지 알지 못하노라"},{"n":17,"t":"그리스도께서 나를 보내심은 침례를 주게 하려 하심이 아니요 오직 복음을 전케 하려 하심이니 말의 지혜로 하지 아니함은 그리스도의 십자가가 헛되지 않게 하려 함이라"},{"n":18,"t":"십자가의 도가 멸망하는 자들에게는 미련한 것이요 구원을 얻는 우리에게는 하나님의 능력이라"},{"n":19,"t":"기록된 바 내가 지혜 있는 자들의 지혜를 멸하고 총명한 자들의 총명을 폐하리라 하였으니"},{"n":20,"t":"지혜 있는 자가 어디 있느뇨 선비가 어디 있느뇨 이 세대에 변사가 어디 있느뇨 하나님께서 이 세상의 지혜를 미련케 하신 것이 아니뇨"},{"n":21,"t":"하나님의 지혜에 있어서는 이 세상이 자기 지혜로 하나님을 알지 못하는 고로 하나님께서 전도의 미련한 것으로 믿는 자들을 구원하시기를 기뻐하셨도다"},{"n":22,"t":"유대인은 표적을 구하고 헬라인은 지혜를 찾으나"},{"n":23,"t":"우리는 십자가에 못 박힌 그리스도를 전하니 유대인에게는 거리끼는 것이요 이방인에게는 미련한 것이로되"},{"n":24,"t":"오직 부르심을 입은 자들에게는 유대인이나 헬라인이나 그리스도는 하나님의 능력이요 하나님의 지혜니라"},{"n":25,"t":"하나님의 미련한 것이 사람보다 지혜 있고 하나님의 약한 것이 사람보다 강하니라"},{"n":26,"t":"형제들아 너희를 부르심을 보라 육체를 따라 지혜 있는 자가 많지 아니하며 능한 자가 많지 아니하며 문벌 좋은 자가 많지 아니하도다"},{"n":27,"t":"그러나 하나님께서 세상의 미련한 것들을 택하사 지혜 있는 자들을 부끄럽게 하려 하시고 세상의 약한 것들을 택하사 강한 것들을 부끄럽게 하려 하시며"},{"n":28,"t":"하나님께서 세상의 천한 것들과 멸시 받는 것들과 없는 것들을 택하사 있는 것들을 폐하려 하시나니"},{"n":29,"t":"이는 아무 육체라도 하나님 앞에서 자랑하지 못하게 하려 하심이라"},{"n":30,"t":"너희는 하나님께로부터 나서 그리스도 예수 안에 있고 예수는 하나님께로서 나와서 우리에게 지혜와 의로움과 거룩함과 구속함이 되셨으니"},{"n":31,"t":"기록된 바 자랑하는 자는 주 안에서 자랑하라 함과 같게 하려 함이니라"}],"kids":[{"n":1,"t":"하나님의 뜻에 따라 그리스도 예수님의 사도로 부름받은 나 바울과, 형제 소스데네는"},{"n":2,"t":"고린도에 있는 하나님의 교회, 곧 그리스도 예수님 안에서 거룩하게 되어 성도(하나님의 백성)로 부름받은 여러분과, 또 어디에서나 우리 주이신 예수 그리스도의 이름을 부르는 모든 사람에게 이 편지를 써요."},{"n":3,"t":"우리 아버지 하나님과 주 예수 그리스도로부터 은혜와 평강(평안)이 여러분에게 함께하기를 빌어요."},{"n":4,"t":"나는 그리스도 예수님을 통해 여러분에게 주신 하나님의 은혜 때문에 늘 여러분을 위해 하나님께 감사드려요."},{"n":5,"t":"여러분은 그리스도 안에서 모든 면에서, 곧 말솜씨와 지식에서도 풍성해졌어요."},{"n":6,"t":"그리하여 그리스도에 대한 증거가 여러분 가운데 든든히 자리 잡았어요."},{"n":7,"t":"그래서 여러분은 어떤 선물(성령께서 주시는 은사)도 부족함이 없이, 우리 주 예수 그리스도께서 다시 나타나실 날을 기다리고 있어요."},{"n":8,"t":"주님께서 우리 주 예수 그리스도께서 다시 오시는 날까지 여러분을 흔들리지 않게 붙들어 주셔서, 그날에 책망받을 일이 없는 사람으로 세워 주실 거예요."},{"n":9,"t":"여러분을 불러 그분의 아들이신 우리 주 예수 그리스도와 사귀게 해 주신 하나님은 신실하신(약속을 꼭 지키시는) 분이세요."},{"n":10,"t":"형제 여러분, 우리 주 예수 그리스도의 이름으로 여러분에게 부탁해요. 모두 같은 말을 하고, 여러분 가운데 다툼이 없이 같은 마음과 같은 뜻으로 온전히 하나가 되세요."},{"n":11,"t":"내 형제들이여, 글로에의 집 사람들이 알려 줘서 들었는데, 여러분 가운데 다툼이 있다고 하더군요."},{"n":12,"t":"내가 말하는 건 이런 거예요. 여러분이 각각 \\"나는 바울 편이다\\", \\"나는 아볼로 편이다\\", \\"나는 게바(베드로) 편이다\\", \\"나는 그리스도 편이다\\" 하고 갈라져 있다는 거예요."},{"n":13,"t":"그리스도가 여럿으로 나뉘셨나요? 바울이 여러분을 위해 십자가에 못 박힌 것도 아니고, 여러분이 바울의 이름으로 침례를 받은 것도 아니잖아요."},{"n":14,"t":"나는 그리스보와 가이오 외에는 여러분 가운데 누구에게도 침례를 주지 않은 것을 감사드려요."},{"n":15,"t":"그래서 아무도 \\"나는 바울의 이름으로 침례를 받았다\\"고 말할 수 없게 되었어요."},{"n":16,"t":"아, 스데바나 집안 사람들에게도 침례를 주었어요. 그 외에는 누구에게 더 주었는지는 잘 기억나지 않아요."},{"n":17,"t":"그리스도께서 나를 보내신 것은 침례를 주게 하시려는 것이 아니라, 오직 복음(기쁜 소식)을 전하게 하시려는 것이에요. 그것도 사람의 말솜씨와 지혜를 자랑하면서 전하는 게 아니에요. 그러면 그리스도의 십자가가 헛되이 되어 버리니까요."},{"n":18,"t":"십자가의 말씀(가르침)은 멸망할 사람들에게는 어리석게 보이지만, 구원받는 우리에게는 하나님의 놀라운 능력이에요."},{"n":19,"t":"성경에 이렇게 적혀 있어요. \\"내가 지혜로운 사람들의 지혜를 없애고, 똑똑하다는 사람들의 똑똑함을 쓸모없게 만들겠다.\\""},{"n":20,"t":"그러니 지혜로운 사람이 어디 있나요? 학자가 어디 있나요? 이 시대의 똑똑한 말꾼이 어디 있나요? 하나님께서는 이 세상의 지혜를 어리석은 것으로 만들어 버리셨어요."},{"n":21,"t":"하나님의 지혜로 보면, 세상은 자기 지혜로는 하나님을 알 수 없어요. 그래서 하나님께서는 어리석어 보이는 복음 전파를 통해 믿는 사람들을 구원하시기를 기뻐하셨어요."},{"n":22,"t":"유대 사람들은 기적 같은 표적을 보여 달라 하고, 헬라(그리스) 사람들은 지혜를 찾아요."},{"n":23,"t":"그러나 우리는 십자가에 못 박히신 그리스도를 전해요. 이것은 유대 사람들에게는 걸려 넘어지게 하는 일이고, 이방 사람들에게는 어리석게 보이는 일이지만,"},{"n":24,"t":"부르심을 받은 사람들, 곧 유대인이든 헬라인이든 그들에게는 그리스도가 바로 하나님의 능력이시고 하나님의 지혜이세요."},{"n":25,"t":"하나님의 어리석어 보이는 것이 사람의 지혜보다 더 지혜롭고, 하나님의 약해 보이는 것이 사람의 힘보다 더 강해요."},{"n":26,"t":"형제 여러분, 하나님께서 여러분을 어떻게 부르셨는지 보세요. 사람의 기준으로 보아 지혜로운 사람이 많지 않고, 힘 있는 사람도 많지 않고, 좋은 집안 출신도 많지 않아요."},{"n":27,"t":"그런데 하나님께서는 세상에서 어리석다는 것들을 택하셔서 지혜 있다는 사람들을 부끄럽게 하시고, 세상에서 약한 것들을 택하셔서 강한 것들을 부끄럽게 하셨어요."},{"n":28,"t":"또 하나님께서는 세상의 보잘것없는 것들, 멸시받는 것들, 아무것도 아닌 것들을 택하셔서 잘난 것처럼 여겨지는 것들을 무너뜨리려 하세요."},{"n":29,"t":"그것은 누구도 하나님 앞에서 자기 자신을 자랑하지 못하게 하시려는 것이에요."},{"n":30,"t":"여러분이 그리스도 예수님 안에 있게 된 것은 하나님께서 하신 일이에요. 예수님께서는 하나님께로부터 우리에게 오셔서 우리의 지혜가 되시고, 의로움(올바름)과 거룩함, 그리고 구원(죄에서 풀어 주심)이 되셨어요."},{"n":31,"t":"그래서 성경에 적힌 것처럼 \\"자랑하려는 사람은 주님 안에서 자랑하라\\"는 말씀이 이루어진 거예요."}]}},{"chapter":2,"title":"성령으로 알리신 지혜","verses":{"krv":[{"n":1,"t":"형제들아 내가 너희에게 나아가 하나님의 증거를 전할 때에 말과 지혜의 아름다운 것으로 아니하였나니"},{"n":2,"t":"내가 너희 중에서 예수 그리스도와 그의 십자가에 못 박히신 것 외에는 아무 것도 알지 아니하기로 작정하였음이라"},{"n":3,"t":"내가 너희 가운데 거할 때에 약하며 두려워하며 심히 떨었노라"},{"n":4,"t":"내 말과 내 전도함이 지혜의 권하는 말로 하지 아니하고 다만 성령의 나타남과 능력으로 하여"},{"n":5,"t":"너희 믿음이 사람의 지혜에 있지 아니하고 다만 하나님의 능력에 있게 하려 하였노라"},{"n":6,"t":"그러나 우리가 온전한 자들 중에서 지혜를 말하노니 이는 이 세상의 지혜가 아니요 또 이 세상의 없어질 관원의 지혜도 아니요"},{"n":7,"t":"오직 비밀한 가운데 있는 하나님의 지혜를 말하는 것이니 곧 감취었던 것인데 하나님이 우리의 영광을 위하사 만세 전에 미리 정하신 것이라"},{"n":8,"t":"이 지혜는 이 세대의 관원이 하나도 알지 못하였나니 만일 알았더면 영광의 주를 십자가에 못 박지 아니하였으리라"},{"n":9,"t":"기록된 바 하나님이 자기를 사랑하는 자들을 위하여 예비하신 모든 것은 눈으로 보지 못하고 귀로도 듣지 못하고 사람의 마음으로도 생각지 못하였다 함과 같으니라"},{"n":10,"t":"오직 하나님이 성령으로 이것을 우리에게 보이셨으니 성령은 모든 것 곧 하나님의 깊은 것이라도 통달하시느니라"},{"n":11,"t":"사람의 사정을 사람의 속에 있는 영 외에는 누가 알리요 이와 같이 하나님의 사정도 하나님의 영 외에는 아무도 알지 못하느니라"},{"n":12,"t":"우리가 세상의 영을 받지 아니하고 오직 하나님께로 온 영을 받았으니 이는 우리로 하여금 하나님께서 우리에게 은혜로 주신 것들을 알게 하려 하심이라"},{"n":13,"t":"우리가 이것을 말하거니와 사람의 지혜의 가르친 말로 아니하고 오직 성령의 가르치신 것으로 하니 신령한 일은 신령한 것으로 분별하느니라"},{"n":14,"t":"육에 속한 사람은 하나님의 성령의 일을 받지 아니하나니 저희에게는 미련하게 보임이요 또 깨닫지도 못하나니 이런 일은 영적으로라야 분변함이니라"},{"n":15,"t":"신령한 자는 모든 것을 판단하나 자기는 아무에게도 판단을 받지 아니하느니라"},{"n":16,"t":"누가 주의 마음을 알아서 주를 가르치겠느냐 그러나 우리가 그리스도의 마음을 가졌느니라"}],"kids":[{"n":1,"t":"형제 여러분, 내가 여러분에게 가서 하나님의 비밀(증거)을 전할 때에, 멋진 말솜씨나 사람의 지혜로 한 것이 아니에요."},{"n":2,"t":"나는 여러분과 함께 있는 동안 예수 그리스도, 그것도 십자가에 못 박히신 그분 외에는 아무것도 모르기로 마음먹었어요."},{"n":3,"t":"내가 여러분과 함께 있을 때, 나는 약하고 두려워하며 몹시 떨었어요."},{"n":4,"t":"내 말과 내 복음 전파는 그럴듯한 지혜의 말로 한 것이 아니라, 성령께서 직접 보여 주시는 능력으로 한 것이에요."},{"n":5,"t":"그래서 여러분의 믿음이 사람의 지혜가 아니라 하나님의 능력 위에 서게 하려고 한 거예요."},{"n":6,"t":"그러나 우리는 믿음에 성숙한 사람들에게는 지혜를 이야기해요. 그것은 이 세상의 지혜도 아니고, 머지않아 사라질 이 세상 권력자들의 지혜도 아니에요."},{"n":7,"t":"우리가 말하는 것은 감추어져 있던 하나님의 비밀한 지혜예요. 그 지혜는 하나님께서 우리에게 영광을 주시려고 세상이 시작되기 전부터 미리 정하신 거예요."},{"n":8,"t":"이 지혜는 이 시대의 권력자들 가운데 누구도 알지 못했어요. 만일 그들이 알았더라면 영광의 주님을 십자가에 못 박지 않았을 거예요."},{"n":9,"t":"성경에 적힌 것처럼, \\"하나님께서 자기를 사랑하는 사람들을 위해 준비해 두신 것들은 눈으로 본 적도 없고, 귀로 들은 적도 없고, 사람의 마음으로 떠올려 본 적도 없는 것이다.\\""},{"n":10,"t":"하나님께서는 그 비밀을 성령을 통해 우리에게 보여 주셨어요. 성령께서는 모든 것을, 심지어 하나님의 깊은 생각까지도 다 살펴 아세요."},{"n":11,"t":"사람의 속마음을 사람 안에 있는 영(마음) 외에는 누가 알 수 있겠어요? 마찬가지로 하나님의 속생각도 하나님의 영 외에는 아무도 알 수 없어요."},{"n":12,"t":"우리가 받은 영은 세상의 영이 아니라, 하나님께로부터 오신 영(성령)이에요. 그것은 하나님께서 우리에게 은혜로 거저 주신 선물들을 우리가 알 수 있게 하시려는 거예요."},{"n":13,"t":"우리는 이것을 말할 때 사람의 지혜가 가르친 말로 하지 않고, 성령께서 가르쳐 주신 말로 해요. 영적인 진리는 영적인 사람에게 영적인 방식으로 설명해야 하니까요."},{"n":14,"t":"육에 속한 사람(성령을 모시지 못한 사람)은 하나님의 성령께서 하시는 일을 받아들이지 못해요. 그런 일이 그들에게는 어리석게 보이고, 깨닫지도 못해요. 영적인 일은 영으로만 분별할 수 있기 때문이에요."},{"n":15,"t":"영적인 사람(성령을 따르는 사람)은 모든 것을 분별할 수 있지만, 자기는 누구에게도 평가받지 않아요."},{"n":16,"t":"\\"누가 주님의 마음을 알아서 주님을 가르치겠는가?\\" 하고 성경에 쓰여 있어요. 그런데 우리에게는 그리스도의 마음이 있어요."}]}},{"chapter":3,"title":"교회의 일꾼과 분쟁","verses":{"krv":[{"n":1,"t":"형제들아 내가 신령한 자들을 대함과 같이 너희에게 말할 수 없어서 육신에 속한 자 곧 그리스도 안에서 어린 아이들을 대함과 같이 하노라"},{"n":2,"t":"내가 너희를 젖으로 먹이고 밥으로 아니하였노니 이는 너희가 감당치 못하였음이거니와 지금도 못하리라"},{"n":3,"t":"너희가 아직도 육신에 속한 자로다 너희 가운데 시기와 분쟁이 있으니 어찌 육신에 속하여 사람을 따라 행함이 아니리요"},{"n":4,"t":"어떤 이는 말하되 나는 바울에게라 하고 다른 이는 나는 아볼로에게라 하니 너희가 사람이 아니리요"},{"n":5,"t":"그런즉 아볼로는 무엇이며 바울은 무엇이뇨 저희는 주께서 각각 주신 대로 너희로 하여금 믿게 한 사역자들이니라"},{"n":6,"t":"나는 심었고 아볼로는 물을 주었으되 오직 하나님은 자라나게 하셨나니"},{"n":7,"t":"그런즉 심는 이나 물 주는 이는 아무 것도 아니로되 오직 자라나게 하시는 하나님뿐이니라"},{"n":8,"t":"심는 이와 물 주는 이가 일반이나 각각 자기의 일하는 대로 자기의 상을 받으리라"},{"n":9,"t":"우리는 하나님의 동역자들이요 너희는 하나님의 밭이요 하나님의 집이니라"},{"n":10,"t":"내게 주신 하나님의 은혜를 따라 내가 지혜로운 건축자와 같이 터를 닦아 두매 다른 이가 그 위에 세우나 그러나 각각 어떻게 그 위에 세우기를 조심할지니라"},{"n":11,"t":"이 닦아 둔 것 외에 능히 다른 터를 닦아 둘 자가 없으니 이 터는 곧 예수 그리스도라"},{"n":12,"t":"만일 누구든지 금이나 은이나 보석이나 나무나 풀이나 짚으로 이 터 위에 세우면"},{"n":13,"t":"각각 공력이 나타날 터인데 그 날이 공력을 밝히리니 이는 불로 나타내고 그 불이 각 사람의 공력이 어떠한 것을 시험할 것임이니라"},{"n":14,"t":"만일 누구든지 그 위에 세운 공력이 그대로 있으면 상을 받고"},{"n":15,"t":"누구든지 공력이 불타면 해를 받으리니 그러나 자기는 구원을 얻되 불 가운데서 얻은 것 같으리라"},{"n":16,"t":"너희가 하나님의 성전인 것과 하나님의 성령이 너희 안에 거하시는 것을 알지 못하느뇨"},{"n":17,"t":"누구든지 하나님의 성전을 더럽히면 하나님이 그 사람을 멸하시리라 하나님의 성전은 거룩하니 너희도 그러하니라"},{"n":18,"t":"아무도 자기를 속이지 말라 너희 중에 누구든지 이 세상에서 지혜 있는 줄로 생각하거든 미련한 자가 되어라 그리하여야 지혜로운 자가 되리라"},{"n":19,"t":"이 세상 지혜는 하나님께 미련한 것이니 기록된 바 지혜 있는 자들로 하여금 자기 궤휼에 빠지게 하시는 이라 하였고"},{"n":20,"t":"또 주께서 지혜 있는 자들의 생각을 헛것으로 아신다 하셨느니라"},{"n":21,"t":"그런즉 누구든지 사람을 자랑하지 말라 만물이 다 너희 것임이라"},{"n":22,"t":"바울이나 아볼로나 게바나 세계나 생명이나 사망이나 지금 것이나 장래 것이나 다 너희의 것이요"},{"n":23,"t":"너희는 그리스도의 것이요 그리스도는 하나님의 것이니라"}],"kids":[{"n":1,"t":"형제 여러분, 나는 여러분에게 영적으로 성숙한 사람들에게 말하듯이 말할 수가 없었어요. 그래서 육신에 속한 사람들, 곧 그리스도 안에서 아직 어린아이 같은 여러분에게 말하듯이 말했어요."},{"n":2,"t":"나는 여러분에게 젖을 먹였지 단단한 음식을 주지 않았어요. 그때 여러분이 단단한 음식을 받을 수 없었기 때문이고, 사실 지금도 여전히 받을 수 없어요."},{"n":3,"t":"여러분은 아직도 육신에 속한 사람이에요. 여러분 가운데 시기와 다툼이 있는데, 그것이 육신에 속하여 보통 사람들이 사는 방식대로 사는 것이 아니고 무엇이겠어요?"},{"n":4,"t":"한 사람은 \\"나는 바울 편이다\\" 하고, 다른 사람은 \\"나는 아볼로 편이다\\" 한다면, 여러분이 그저 평범한 사람과 다를 게 무엇인가요?"},{"n":5,"t":"그러면 아볼로는 누구이고 바울은 누구인가요? 우리는 주님께서 각자에게 맡겨 주신 일을 따라, 여러분이 믿게 되도록 도운 일꾼들일 뿐이에요."},{"n":6,"t":"나는 심었고 아볼로는 물을 주었지만, 자라게 하신 분은 하나님이세요."},{"n":7,"t":"그러니 심는 사람이나 물 주는 사람은 별것 아니고, 오직 자라게 하시는 하나님만이 중요하세요."},{"n":8,"t":"심는 사람과 물 주는 사람은 한 팀이지만, 각자 자기가 일한 만큼 자기 상(보상)을 받게 될 거예요."},{"n":9,"t":"우리는 하나님과 함께 일하는 일꾼들이고, 여러분은 하나님의 밭이고 하나님의 집(건물)이에요."},{"n":10,"t":"하나님께서 내게 주신 은혜를 따라, 나는 지혜로운 건축가처럼 기초(터)를 놓았고 다른 사람이 그 위에 집을 세워요. 그러나 각자 그 위에 어떻게 세우는지 잘 살펴야 해요."},{"n":11,"t":"이미 놓은 기초 외에는 누구도 다른 기초를 놓을 수 없어요. 그 기초는 바로 예수 그리스도세요."},{"n":12,"t":"누구든지 이 기초 위에 금이나 은이나 보석으로 짓든, 아니면 나무나 풀이나 짚으로 짓든,"},{"n":13,"t":"각자가 한 일이 그대로 드러날 거예요. 심판의 그 날이 그것을 환히 밝힐 텐데, 그것은 불로 드러나며, 그 불이 각 사람이 한 일이 어떤 것이었는지 시험해 줄 거예요."},{"n":14,"t":"만일 누군가 그 기초 위에 세운 일이 불에도 그대로 남아 있으면, 그 사람은 상(보상)을 받을 거예요."},{"n":15,"t":"만일 누군가의 일이 다 타 버리면 그 사람은 손해를 보겠지만, 그 사람 자신은 구원을 받을 거예요. 다만 마치 불 속에서 겨우 빠져나온 것처럼 그렇게 될 거예요."},{"n":16,"t":"여러분은 자기 자신이 하나님의 성전이고, 하나님의 성령께서 여러분 안에 살고 계신다는 것을 알지 못하나요?"},{"n":17,"t":"누구든지 하나님의 성전을 망가뜨리면 하나님께서 그 사람을 망하게 하실 거예요. 하나님의 성전은 거룩한데, 여러분이 바로 그 성전이에요."},{"n":18,"t":"누구도 스스로를 속이지 마세요. 여러분 가운데 누구든지 자기가 이 세상에서 지혜롭다고 생각한다면, 차라리 어리석은 사람이 되세요. 그래야 정말 지혜로운 사람이 될 수 있어요."},{"n":19,"t":"이 세상의 지혜는 하나님 보시기에 어리석은 것이에요. 성경에 \\"하나님께서 지혜로운 사람들을 그들 자신의 꾀에 빠뜨리신다\\" 하고 적혀 있고,"},{"n":20,"t":"또 \\"주님께서는 지혜로운 사람들의 생각이 헛되다는 것을 아신다\\"고도 적혀 있어요."},{"n":21,"t":"그러므로 누구도 사람을 자랑하지 마세요. 모든 것이 다 여러분의 것이에요."},{"n":22,"t":"바울이든, 아볼로든, 게바(베드로)든, 세상이든, 생명이든, 죽음이든, 지금 있는 것이든, 앞으로 올 것이든, 모두 다 여러분의 것이에요."},{"n":23,"t":"그리고 여러분은 그리스도의 것이고, 그리스도는 하나님의 것이세요."}]}},{"chapter":4,"title":"사도의 본보기","verses":{"krv":[{"n":1,"t":"사람이 마땅히 우리를 그리스도의 일꾼이요 하나님의 비밀을 맡은 자로 여길지어다"},{"n":2,"t":"그리고 맡은 자들에게 구할 것은 충성이니라"},{"n":3,"t":"너희에게나 다른 사람에게나 판단 받는 것이 내게는 매우 작은 일이라 나도 나를 판단치 아니하노니"},{"n":4,"t":"내가 자책할 아무 것도 깨닫지 못하나 그러나 이를 인하여 의롭다 함을 얻지 못하노라 다만 나를 판단하실 이는 주시니라"},{"n":5,"t":"그러므로 때가 이르기 전 곧 주께서 오시기까지 아무 것도 판단치 말라 그가 어두움에 감추인 것들을 드러내고 마음의 뜻을 나타내시리니 그 때에 각 사람에게 하나님께로부터 칭찬이 있으리라"},{"n":6,"t":"형제들아 내가 너희를 위하여 이 일에 나와 아볼로를 가지고 본을 보였으니 이는 너희로 하여금 기록한 말씀 밖에 넘어가지 말라 한 것을 우리에게서 배워 서로 대적하여 교만한 마음을 먹지 말게 하려 함이라"},{"n":7,"t":"누가 너를 구별하였느뇨 네게 있는 것 중에 받지 아니한 것이 무엇이뇨 네가 받았은즉 어찌하여 받지 아니한 것 같이 자랑하느뇨"},{"n":8,"t":"너희가 이미 배부르며 이미 부요하며 우리 없이 왕 노릇 하였도다 우리가 너희와 함께 왕 노릇 하기 위하여 참으로 너희의 왕 노릇 하기를 원하노라"},{"n":9,"t":"내가 생각건대 하나님이 사도인 우리를 죽이기로 작정한 자 같이 미말에 두셨으매 우리는 세계 곧 천사와 사람에게 구경거리가 되었노라"},{"n":10,"t":"우리는 그리스도의 연고로 미련하되 너희는 그리스도 안에서 지혜롭고 우리는 약하되 너희는 강하고 너희는 존귀하되 우리는 비천하여"},{"n":11,"t":"바로 이 시간까지 우리가 주리고 목마르며 헐벗고 매맞으며 정처가 없고"},{"n":12,"t":"또 수고하여 친히 손으로 일을 하며 후욕을 당한즉 축복하고 핍박을 당한즉 참고"},{"n":13,"t":"비방을 당한즉 권면하니 우리가 지금까지 세상의 더러운 것과 만물의 찌끼 같이 되었도다"},{"n":14,"t":"내가 너희를 부끄럽게 하려고 이것을 쓰는 것이 아니라 오직 너희를 내 사랑하는 자녀 같이 권하려 하는 것이라"},{"n":15,"t":"그리스도 안에서 일만 스승이 있으되 아비는 많지 아니하니 그리스도 예수 안에서 복음으로써 내가 너희를 낳았음이라"},{"n":16,"t":"그러므로 내가 너희에게 권하노니 너희는 나를 본받는 자 되라"},{"n":17,"t":"이를 인하여 내가 주 안에서 내 사랑하고 신실한 아들 디모데를 너희에게 보내었노니 저가 너희로 하여금 그리스도 예수 안에서 나의 행사 곧 내가 각처 교회에서 가르치는 것을 생각나게 하리라"},{"n":18,"t":"어떤 이들은 내가 너희에게 나아가지 아니할 것 같이 스스로 교만하여졌으나"},{"n":19,"t":"그러나 주께서 허락하시면 내가 너희에게 속히 나아가서 교만한 자의 말을 알아 볼 것이 아니라 오직 그 능력을 알아 보겠노니"},{"n":20,"t":"하나님의 나라는 말에 있지 아니하고 오직 능력에 있음이라"},{"n":21,"t":"너희가 무엇을 원하느냐 내가 매를 가지고 너희에게 나아가랴 사랑과 온유한 마음으로 나아가랴"}],"kids":[{"n":1,"t":"그러니 사람들은 마땅히 우리를 그리스도의 일꾼이요, 하나님의 비밀을 맡은 종으로 여겨야 해요."},{"n":2,"t":"맡은 일을 하는 사람에게 가장 중요한 것은 충성(끝까지 신실함)이에요."},{"n":3,"t":"여러분이나 다른 사람들이 나를 평가하는 것은 내게는 매우 작은 일이에요. 사실 나도 나 스스로를 평가하지 않아요."},{"n":4,"t":"내 양심에 거리낄 만한 것이 떠오르지는 않지만, 그렇다고 해서 그것 때문에 내가 의롭다는 인정을 받는 것은 아니에요. 나를 판단하실 분은 오직 주님이세요."},{"n":5,"t":"그러므로 때가 되기 전에는, 곧 주님께서 오시기 전에는 아무것도 함부로 판단하지 마세요. 주님께서 어둠 속에 감추어진 것들을 드러내시고, 사람들의 속마음까지 환히 드러내실 거예요. 그때 각 사람이 하나님께로부터 받을 칭찬을 받게 될 거예요."},{"n":6,"t":"형제 여러분, 나는 여러분을 위해 나와 아볼로를 본보기로 들어 이렇게 말한 거예요. 여러분이 우리를 보고 \\"성경에 적혀 있는 말씀의 한계를 넘지 마라\\"는 가르침을 배워서, 어느 한 사람을 편들면서 다른 사람을 헐뜯고 우쭐거리는 일이 없게 하려는 거예요."},{"n":7,"t":"누가 당신을 다른 사람보다 특별하게 만들었나요? 당신이 가진 것 중에 받지 않은 것이 무엇이 있나요? 받았다면, 왜 마치 받지 않은 것처럼 자랑하나요?"},{"n":8,"t":"여러분은 벌써 다 배부르고, 벌써 다 부유하며, 우리 없이도 이미 왕처럼 살고 있군요! 정말 여러분이 왕이 되었으면 좋겠어요. 그러면 우리도 여러분과 함께 왕처럼 누릴 수 있을 테니까요."},{"n":9,"t":"내가 생각하기에는, 하나님께서는 사도인 우리를 사형 선고를 받은 사람처럼 가장 끝자리에 세워 두신 것 같아요. 우리는 온 세상, 곧 천사들과 사람들에게 구경거리가 되었어요."},{"n":10,"t":"우리는 그리스도 때문에 어리석은 사람이 되었지만, 여러분은 그리스도 안에서 지혜롭다고 해요. 우리는 약하지만 여러분은 강하다고 하고, 여러분은 존귀하지만 우리는 보잘것없는 사람이 되었어요."},{"n":11,"t":"바로 이 시간까지도 우리는 굶주리고 목마르고 옷도 변변치 않고 매를 맞고 머무를 곳도 없이 떠돌고 있어요."},{"n":12,"t":"또 우리는 직접 손으로 힘들게 일하며, 욕을 들어도 축복으로 갚고, 박해를 당해도 참아 내요."},{"n":13,"t":"우리는 험한 말을 들어도 부드럽게 권면해요. 우리는 지금까지 세상의 쓰레기처럼, 모든 것 가운데 가장 천한 찌꺼기처럼 취급받고 있어요."},{"n":14,"t":"내가 이런 말을 하는 것은 여러분을 부끄럽게 하려는 게 아니라, 사랑하는 내 자녀처럼 여러분을 타이르려는 거예요."},{"n":15,"t":"여러분에게 그리스도 안에서 가르치는 선생은 만 명이라도 있을지 모르지만, 아버지는 많지 않아요. 그리스도 예수님 안에서 복음으로 내가 여러분의 영적 아버지가 되었어요."},{"n":16,"t":"그러니 부탁해요. 여러분은 나를 본받는 사람이 되세요."},{"n":17,"t":"이 일을 위해 내가 주님 안에서 사랑하고 신실한 내 아들 디모데를 여러분에게 보냈어요. 디모데는 내가 그리스도 예수님 안에서 어떻게 살고 있는지, 또 내가 어디든 가는 교회마다 무엇을 가르치는지를 여러분에게 다시 일깨워 줄 거예요."},{"n":18,"t":"어떤 사람들은 내가 여러분에게 가지 않을 거라고 생각하면서 우쭐거리고 있어요."},{"n":19,"t":"그러나 주님께서 허락하시면 나는 곧 여러분에게 갈 거예요. 그때는 그 우쭐대는 사람들이 무슨 말을 하는지가 아니라 무슨 능력을 가지고 있는지를 살펴볼 거예요."},{"n":20,"t":"하나님의 나라는 말에 있지 않고 능력에 있기 때문이에요."},{"n":21,"t":"여러분은 무엇을 원하나요? 내가 매를 들고 여러분에게 가는 것이 좋은가요? 아니면 사랑과 부드러운 마음으로 가는 것이 좋은가요?"}]}},{"chapter":5,"title":"음행한 자에 대한 권징","verses":{"krv":[{"n":1,"t":"너희 중에 심지어 음행이 있다 함을 들으니 이런 음행은 이방인 중에라도 없는 것이라 누가 그 아비의 아내를 취하였다 하는도다"},{"n":2,"t":"그리하고도 너희가 오히려 교만하여져서 어찌하여 통한히 여기지 아니하고 그 일 행한 자를 너희 중에서 물리치지 아니하였느냐"},{"n":3,"t":"내가 실로 몸으로는 떠나 있으나 영으로는 함께 있어서 거기 있는 것 같이 이 일 행한 자를 이미 판단하였노라"},{"n":4,"t":"주 예수의 이름으로 너희가 내 영과 함께 모여서 우리 주 예수의 능력으로"},{"n":5,"t":"이런 자를 사단에게 내어주었으니 이는 육신은 멸하고 영은 주 예수의 날에 구원 얻게 하려 함이라"},{"n":6,"t":"너희의 자랑하는 것이 옳지 아니하도다 적은 누룩이 온 덩어리에 퍼지는 것을 알지 못하느냐"},{"n":7,"t":"너희는 누룩 없는 자인데 새 덩어리가 되기 위하여 묵은 누룩을 내어 버리라 우리의 유월절 양 곧 그리스도께서 희생이 되셨느니라"},{"n":8,"t":"이러므로 우리가 명절을 지키되 묵은 누룩도 말고 괴악하고 악독한 누룩도 말고 오직 순전함과 진실함의 누룩 없는 떡으로 하자"},{"n":9,"t":"내가 너희에게 쓴 것에 음행하는 자들을 사귀지 말라 하였거니와"},{"n":10,"t":"이 말은 이 세상의 음행하는 자들이나 탐하는 자들과 토색하는 자들이나 우상 숭배하는 자들을 도무지 사귀지 말라 하는 것이 아니니 만일 그리하려면 세상 밖으로 나가야 할 것이라"},{"n":11,"t":"이제 내가 너희에게 쓴 것은 만일 어떤 형제라 일컫는 자가 음행하거나 탐람하거나 우상 숭배를 하거나 후욕하거나 술 취하거나 토색하거든 사귀지도 말고 그런 자와는 함께 먹지도 말라 함이라"},{"n":12,"t":"외인들을 판단하는데 내게 무슨 상관이 있으리요마는 교중 사람들이야 너희가 판단치 아니하랴"},{"n":13,"t":"외인들은 하나님이 판단하시려니와 이 악한 사람은 너희 중에서 내어 쫓으라"}],"kids":[{"n":1,"t":"여러분 가운데 심지어 음행(부도덕한 성적인 죄)까지 있다는 소문을 들었어요. 그것도 이방 사람들 중에서도 없는 종류의 음행이에요. 어떤 사람이 자기 아버지의 아내(계모)를 데리고 산다는 거예요."},{"n":2,"t":"그러고도 여러분은 슬퍼하기는커녕 오히려 우쭐거리고 있어요. 어떻게 그 일을 한 사람을 여러분 가운데서 내쫓지 않고 그냥 두고 있나요?"},{"n":3,"t":"나는 비록 몸으로는 여러분과 떨어져 있지만, 영으로는 여러분과 함께 있어서, 마치 그곳에 있는 것처럼 그 일을 한 사람을 이미 판단했어요."},{"n":4,"t":"여러분이 우리 주 예수님의 이름으로 모일 때, 내 영도 함께 그 자리에 있을 거예요. 우리 주 예수님의 능력으로,"},{"n":5,"t":"그런 사람을 사탄에게 넘겨주세요. 그것은 그의 육신은 망하더라도, 그의 영혼은 주 예수님께서 다시 오시는 날에 구원받게 하려는 것이에요."},{"n":6,"t":"여러분이 자랑하는 것은 옳지 않아요. 적은 누룩(빵을 부풀게 하는 발효 가루)이 반죽 전체를 부풀게 한다는 사실을 모르나요?"},{"n":7,"t":"여러분은 누룩 없는 새 반죽처럼 깨끗한 사람들이니, 묵은 누룩(옛 죄)을 다 버려서 새 반죽이 되세요. 우리의 유월절 양이신 그리스도께서 이미 우리를 위해 희생제물이 되셨어요."},{"n":8,"t":"그러니 우리도 명절(유월절)을 지키되, 묵은 누룩이나 악하고 흉한 누룩이 아니라, 오직 순결함과 진실함의 누룩 없는 떡으로 지킵시다."},{"n":9,"t":"내가 전에 보낸 편지에 음행하는 사람들과 어울리지 말라고 썼어요."},{"n":10,"t":"내가 그렇게 쓴 것은 이 세상의 음행하는 사람이나 욕심 많은 사람, 남의 것을 빼앗는 사람, 우상을 섬기는 사람과 절대 어울리지 말라는 뜻이 아니에요. 만약 그렇다면 여러분은 아예 세상 밖으로 나가야 할 거예요."},{"n":11,"t":"내가 지금 쓰는 말은 이거예요. 어떤 사람이 형제(믿는 사람)라고 자처하면서 음행을 하거나, 욕심을 부리거나, 우상을 섬기거나, 남을 욕하거나, 술에 취하거나, 남의 것을 빼앗는다면, 그런 사람과는 어울리지 말고 함께 식사도 하지 마세요."},{"n":12,"t":"교회 밖의 사람들을 판단하는 것은 내가 할 일이 아니에요. 그러나 교회 안의 사람들은 여러분이 판단해야 하지 않겠어요?"},{"n":13,"t":"교회 밖의 사람들은 하나님께서 판단하실 거예요. 그러니 \\"그 악한 사람을 여러분 가운데서 내쫓으세요.\\""}]}},{"chapter":6,"title":"성도 간의 송사와 음행","verses":{"krv":[{"n":1,"t":"너희 중에 누가 다른 이로 더불어 일이 있는데 구태여 불의한 자들 앞에서 송사하고 성도 앞에서 하지 아니하느냐"},{"n":2,"t":"성도가 세상을 판단할 것을 너희가 알지 못하느냐 세상도 너희에게 판단을 받겠거든 지극히 작은 일 판단하기를 감당치 못하겠느냐"},{"n":3,"t":"우리가 천사를 판단할 것을 너희가 알지 못하느냐 그러하거든 하물며 세상 일이랴"},{"n":4,"t":"그런즉 너희가 세상 사건이 있을 때에 교회에서 경히 여김을 받는 자들을 세우느냐"},{"n":5,"t":"내가 너희를 부끄럽게 하려 하여 이 말을 하노니 너희 가운데 그 형제간 일을 판단할 만한 지혜있는 자가 이같이 하나도 없느냐"},{"n":6,"t":"형제가 형제로 더불어 송사할 뿐더러 믿지 아니하는 자들 앞에서 하느냐"},{"n":7,"t":"너희가 피차 송사함으로 너희 가운데 이미 완연한 허물이 있나니 차라리 불의를 당하는 것이 낫지 아니하며 차라리 속는 것이 낫지 아니하냐"},{"n":8,"t":"너희는 불의를 행하고 속이는구나 저는 너희 형제로다"},{"n":9,"t":"불의한 자가 하나님의 나라를 유업으로 받지 못할 줄을 알지 못하느냐 미혹을 받지 말라 음란하는 자나 우상 숭배하는 자나 간음하는 자나 탐색하는 자나 남색하는 자나"},{"n":10,"t":"도적이나 탐람하는 자나 술취하는 자나 후욕하는 자나 토색하는 자들은 하나님의 나라를 유업으로 받지 못하리라"},{"n":11,"t":"너희 중에 이와 같은 자들이 있더니 주 예수 그리스도의 이름과 우리 하나님의 성령 안에서 씻음과 거룩함과 의롭다 하심을 얻었느니라"},{"n":12,"t":"모든 것이 내게 가하나 다 유익한 것이 아니요 모든 것이 내게 가하나 내가 아무에게든지 제재를 받지 아니하리라"},{"n":13,"t":"식물은 배를 위하고 배는 식물을 위하나 하나님이 이것 저것 다 폐하시리라 몸은 음란을 위하지 않고 오직 주를 위하며 주는 몸을 위하시느니라"},{"n":14,"t":"하나님이 주를 다시 살리셨고 또한 그의 권능으로 우리를 다시 살리시리라"},{"n":15,"t":"너희 몸이 그리스도의 지체인 줄을 알지 못하느냐 내가 그리스도의 지체를 가지고 창기의 지체를 만들겠느냐 결코 그럴 수 없느니라"},{"n":16,"t":"창기와 합하는 자는 저와 한 몸인 줄을 알지 못하느냐 일렀으되 둘이 한 육체가 된다 하셨나니"},{"n":17,"t":"주와 합하는 자는 한 영이니라"},{"n":18,"t":"음행을 피하라 사람이 범하는 죄마다 몸 밖에 있거니와 음행하는 자는 자기 몸에게 죄를 범하느니라"},{"n":19,"t":"너희 몸은 너희가 하나님께로부터 받은 바 너희 가운데 계신 성령의 전인 줄을 알지 못하느냐 너희는 너희의 것이 아니라"},{"n":20,"t":"값으로 산 것이 되었으니 그런즉 너희 몸으로 하나님께 영광을 돌리라"}],"kids":[{"n":1,"t":"여러분 가운데 누가 다른 사람과 다툴 일이 생기면, 어째서 성도들 앞에서 해결하지 않고 굳이 믿지 않는 사람들(법정) 앞으로 가서 재판을 받나요?"},{"n":2,"t":"성도들이 장차 세상을 심판하게 될 것을 모르나요? 세상도 여러분에게 심판을 받을 텐데, 이런 작은 문제 하나 판단할 능력이 없겠어요?"},{"n":3,"t":"우리가 천사들도 심판하게 될 것을 모르나요? 그렇다면 이 세상의 일들이야 더 말할 필요도 없잖아요?"},{"n":4,"t":"그러므로 여러분이 이런 세상일로 다툴 일이 생기면, 교회에서 별로 인정받지 못하는 사람을 재판관으로 세우기라도 하라는 건가요?"},{"n":5,"t":"내가 여러분을 부끄럽게 하려고 이 말을 하는 거예요. 여러분 가운데 형제들 사이의 일을 판단해 줄 만한 지혜로운 사람이 정말 한 사람도 없나요?"},{"n":6,"t":"그래서 형제가 형제와 다투는 것도 모자라, 그것을 믿지 않는 사람들 앞에서 따져 본단 말이에요?"},{"n":7,"t":"여러분이 서로 송사를 하고 있다는 것 자체가 이미 큰 잘못이에요. 차라리 손해를 당하는 게 더 낫지 않을까요? 차라리 속는 게 더 낫지 않을까요?"},{"n":8,"t":"그런데 여러분은 오히려 자기가 손해를 끼치고 속이고 있어요. 그것도 형제를요!"},{"n":9,"t":"불의한 사람들은 하나님의 나라를 유산으로 받지 못한다는 것을 모르나요? 속지 마세요. 음란한 사람, 우상을 섬기는 사람, 간음하는 사람, 동성과 부도덕한 성관계를 하는 사람,"},{"n":10,"t":"도둑질하는 사람, 욕심 많은 사람, 술 취하는 사람, 남을 욕하는 사람, 남의 것을 빼앗는 사람은 하나님의 나라를 유산으로 받지 못해요."},{"n":11,"t":"여러분 가운데 전에는 그런 사람이 있었어요. 그러나 여러분은 주 예수 그리스도의 이름과 우리 하나님의 성령 안에서 깨끗이 씻겨졌고, 거룩하게 되었으며, 의롭다는 인정을 받았어요."},{"n":12,"t":"\\"모든 것이 내게 허락되어 있다\\"고 말할 수 있어요. 그러나 모든 것이 다 유익한 것은 아니에요. \\"모든 것이 내게 허락되어 있다\\"고 해도, 나는 어떤 것에도 끌려 다니며 종이 되지 않을 거예요."},{"n":13,"t":"\\"음식은 배를 위해 있고 배는 음식을 위해 있다\\"고 하지만, 하나님께서는 이 둘을 다 없애 버리실 거예요. 그러나 우리 몸은 음행을 위해 있는 것이 아니라 주님을 위해 있는 것이고, 주님께서는 우리 몸을 위해 계세요."},{"n":14,"t":"하나님께서 주님을 다시 살리신 것처럼, 우리도 하나님의 능력으로 다시 살리실 거예요."},{"n":15,"t":"여러분의 몸이 그리스도의 몸의 부분(지체)이라는 것을 모르나요? 그런데 내가 그리스도의 몸의 일부를 떼어 내어 음란한 여자(창기)와 한 몸이 되게 할 수 있을까요? 절대로 그럴 수 없어요."},{"n":16,"t":"음란한 여자와 한 몸이 되는 사람은 그 여자와 한 몸이 된다는 것을 모르나요? 성경에 \\"둘이 한 몸이 된다\\"고 적혀 있어요."},{"n":17,"t":"그러나 주님과 하나로 결합되는 사람은 주님과 한 영이 돼요."},{"n":18,"t":"음행을 멀리하세요. 사람이 짓는 다른 모든 죄는 몸 밖에서 일어나지만, 음행을 하는 사람은 자기 몸 자체에 죄를 짓는 거예요."},{"n":19,"t":"여러분의 몸이 하나님께로부터 받은 성령께서 머무시는 성전이라는 것을 모르나요? 여러분은 더 이상 여러분 자신의 것이 아니에요."},{"n":20,"t":"여러분은 값을 치르고 산 사람들이에요. 그러므로 여러분의 몸으로 하나님께 영광을 돌리세요."}]}},{"chapter":7,"title":"결혼에 관한 권면","verses":{"krv":[{"n":1,"t":"너희의 쓴 말에 대하여는 남자가 여자를 가까이 아니함이 좋으나"},{"n":2,"t":"음행의 연고로 남자마다 자기 아내를 두고 여자마다 자기 남편을 두라"},{"n":3,"t":"남편은 그 아내에게 대한 의무를 다하고 아내도 그 남편에게 그렇게 할지라"},{"n":4,"t":"아내가 자기 몸을 주장하지 못하고 오직 그 남편이 하며 남편도 이와 같이 자기 몸을 주장하지 못하고 오직 그 아내가 하나니"},{"n":5,"t":"서로 분방하지 말라 다만 기도할 틈을 얻기 위하여 합의상 얼마 동안은 하되 다시 합하라 이는 너희의 절제 못함을 인하여 사단으로 너희를 시험하지 못하게 하려 함이라"},{"n":6,"t":"그러나 내가 이 말을 함은 권도요 명령은 아니라"},{"n":7,"t":"나는 모든 사람이 나와 같기를 원하노라 그러나 각각 하나님께 받은 자기의 은사가 있으니 하나는 이러하고 하나는 저러하니라"},{"n":8,"t":"내가 혼인하지 아니한 자들과 및 과부들에게 이르노니 나와 같이 그냥 지내는 것이 좋으니라"},{"n":9,"t":"만일 절제할 수 없거든 혼인하라 정욕이 불 같이 타는 것보다 혼인하는 것이 나으니라"},{"n":10,"t":"혼인한 자들에게 내가 명하노니 (명하는 자는 내가 아니요 주시라) 여자는 남편에게서 갈리지 말고"},{"n":11,"t":"(만일 갈릴지라도 그냥 지내든지 다시 그 남편과 화합하든지 하라) 남편도 아내를 버리지 말라"},{"n":12,"t":"그 남은 사람들에게 내가 말하노니 (이는 주의 명령이 아니라) 만일 어떤 형제에게 믿지 아니하는 아내가 있어 남편과 함께 살기를 좋아하거든 저를 버리지 말며"},{"n":13,"t":"어떤 여자에게 믿지 아니하는 남편이 있어 아내와 함께 살기를 좋아하거든 그 남편을 버리지 말라"},{"n":14,"t":"믿지 아니하는 남편이 아내로 인하여 거룩하게 되고 믿지 아니하는 아내가 남편으로 인하여 거룩하게 되나니 그렇지 아니하면 너희 자녀도 깨끗지 못하니라 그러나 이제 거룩하니라"},{"n":15,"t":"혹 믿지 아니하는 자가 갈리거든 갈리게 하라 형제나 자매나 이런 일에 구속 받을 것이 없느니라 그러나 하나님은 화평 중에서 너희를 부르셨느니라"},{"n":16,"t":"아내 된 자여 네가 남편을 구원할는지 어찌 알 수 있으며 남편된 자여 네가 네 아내를 구원할는지 어찌 알 수 있으리요"},{"n":17,"t":"오직 주께서 각 사람에게 나눠주신 대로 하나님이 각 사람을 부르신 그대로 행하라 내가 모든 교회에서 이와 같이 명하노라"},{"n":18,"t":"할례자로 부르심을 받은 자가 있느냐 무할례자가 되지 말며 무할례자로 부르심을 받은 자가 있느냐 할례를 받지 말라"},{"n":19,"t":"할례 받는 것도 아무 것도 아니요 할례 받지 아니하는 것도 아무 것도 아니로되 오직 하나님의 계명을 지킬 따름이니라"},{"n":20,"t":"각 사람이 부르심을 받은 그 부르심 그대로 지내라"},{"n":21,"t":"네가 종으로 있을 때에 부르심을 받았느냐 염려하지 말라 그러나 자유할 수 있거든 차라리 사용하라"},{"n":22,"t":"주 안에서 부르심을 받은 자는 종이라도 주께 속한 자유자요 또 이와 같이 자유자로 있을 때에 부르심을 받은 자는 그리스도의 종이니라"},{"n":23,"t":"너희는 값으로 사신 것이니 사람들의 종이 되지 말라"},{"n":24,"t":"형제들아 각각 부르심을 받은 그대로 하나님과 함께 거하라"},{"n":25,"t":"처녀에 대하여는 내가 주께 받은 계명이 없으되 주의 자비하심을 받아서 충성된 자가 되어 의견을 고하노니"},{"n":26,"t":"내 생각에는 이것이 좋으니 곧 임박한 환난을 인하여 사람이 그냥 지내는 것이 좋으니라"},{"n":27,"t":"네가 아내에게 매였느냐 놓이기를 구하지 말며 아내에게서 놓였느냐 아내를 구하지 말라"},{"n":28,"t":"그러나 장가 가도 죄 짓는 것이 아니요 처녀가 시집 가도 죄 짓는 것이 아니로되 이런 이들은 육신에 고난이 있으리니 나는 너희를 아끼노라"},{"n":29,"t":"형제들아 내가 이 말을 하노니 때가 단축하여진 고로 이후부터 아내 있는 자들은 없는 자 같이 하며"},{"n":30,"t":"우는 자들은 울지 않는 자 같이 하며 기쁜 자들은 기쁘지 않은 자 같이 하며 매매하는 자들은 없는 자 같이 하며"},{"n":31,"t":"세상 물건을 쓰는 자들은 다 쓰지 못하는 자 같이 하라 이 세상의 형적은 지나감이니라"},{"n":32,"t":"너희가 염려 없기를 원하노라 장가 가지 않은 자는 주의 일을 염려하여 어찌하여야 주를 기쁘시게 할꼬 하되"},{"n":33,"t":"장가 간 자는 세상 일을 염려하여 어찌하여야 아내를 기쁘게 할꼬 하여 마음이 나누이며"},{"n":34,"t":"시집 가지 않은 자와 처녀는 주의 일을 염려하여 몸과 영을 다 거룩하게 하려 하되 시집 간 자는 세상 일을 염려하여 어찌하여야 남편을 기쁘게 할꼬 하느니라"},{"n":35,"t":"내가 이것을 말함은 너희의 유익을 위함이요 너희에게 올무를 놓으려 함이 아니니 오직 너희로 하여금 이치에 합하게 하여 분요함이 없이 주를 섬기게 하려 함이라"},{"n":36,"t":"누가 자기의 처녀 딸에 대한 일이 이치에 합당치 못한 줄로 생각할 때에 혼기도 지나고 그같이 할 필요가 있거든 마음대로 하라 이것은 죄 짓는 것이 아니니 혼인하게 하라"},{"n":37,"t":"그러나 그 마음을 굳게 하고 또 부득이한 일도 없고 자기 뜻대로 할 권리가 있어서 그 처녀 딸을 머물러 두기로 마음에 작정하여도 잘 하는 것이니라"},{"n":38,"t":"그러므로 처녀 딸을 시집 보내는 자도 잘 하거니와 시집 보내지 아니하는 자가 더 잘 하는 것이니라"},{"n":39,"t":"아내가 그 남편이 살 동안에 매여 있다가 남편이 죽으면 자유하여 자기 뜻대로 시집 갈 것이나 주 안에서만 할 것이니라"},{"n":40,"t":"그러나 내 뜻에는 그냥 지내는 것이 더욱 복이 있으리로다 나도 또한 하나님의 영을 받은 줄로 생각하노라"}],"kids":[{"n":1,"t":"여러분이 편지로 물어본 일에 대해 말할게요. \\"남자가 여자(아내)를 가까이하지 않는 것이 좋다\\"는 말이 있지요."},{"n":2,"t":"그러나 음행을 피하기 위해, 남자는 누구나 자기 아내를 두고 여자도 누구나 자기 남편을 두는 것이 좋아요."},{"n":3,"t":"남편은 아내에게 마땅히 해야 할 도리를 다하고, 아내도 남편에게 그렇게 해야 해요."},{"n":4,"t":"아내의 몸은 자기 마음대로 할 수 있는 것이 아니라 남편의 것이고, 마찬가지로 남편의 몸도 자기 마음대로 할 수 있는 것이 아니라 아내의 것이에요."},{"n":5,"t":"서로 잠자리를 거절하지 마세요. 다만 기도에 더 집중하기 위해 서로 합의해서 한동안 떨어져 있는 것은 괜찮지만, 그 후에는 다시 함께 지내세요. 그것은 여러분이 자제하지 못해서 사탄이 여러분을 시험하지 못하게 하기 위해서예요."},{"n":6,"t":"내가 이렇게 말하는 것은 양해를 구하는 것이지 명령이 아니에요."},{"n":7,"t":"나는 모든 사람이 나처럼 (혼자 지냈으면) 좋겠어요. 그러나 사람마다 하나님께 받은 자기만의 선물(은사)이 있어서, 어떤 사람은 이런 선물을, 어떤 사람은 저런 선물을 받았어요."},{"n":8,"t":"결혼하지 않은 사람들과 과부들에게는 이렇게 말해요. 나처럼 그대로 혼자 지내는 게 좋아요."},{"n":9,"t":"그러나 자제할 수 없거든 결혼하세요. 정욕에 시달리면서 불처럼 타는 것보다는 결혼하는 게 나아요."},{"n":10,"t":"결혼한 사람들에게는 (이것은 내가 아니라 주님께서) 명령하세요. 아내는 남편을 떠나지 마세요."},{"n":11,"t":"(만일 떠나게 되더라도 그대로 혼자 지내든지, 아니면 남편과 다시 화해하세요.) 남편도 아내를 버리면 안 돼요."},{"n":12,"t":"나머지 사람들에게는 내가 말해요(이것은 주님의 명령이 아니에요). 어떤 형제에게 믿지 않는 아내가 있는데 그 아내가 남편과 함께 살기를 원한다면, 그 아내를 버리지 마세요."},{"n":13,"t":"또 어떤 여자에게 믿지 않는 남편이 있는데 그 남편이 아내와 함께 살기를 원한다면, 그 남편을 버리지 마세요."},{"n":14,"t":"믿지 않는 남편이 믿는 아내 덕분에 거룩하게 되고, 믿지 않는 아내도 믿는 남편 덕분에 거룩하게 돼요. 그렇지 않으면 여러분의 자녀들도 깨끗하지 못하겠지만, 사실은 자녀들도 거룩해요."},{"n":15,"t":"그러나 믿지 않는 쪽이 갈라서기를 원한다면 갈라서게 두세요. 형제든 자매든 그런 경우에는 매여 있을 필요가 없어요. 하나님께서는 우리를 평화 속에서 살라고 부르셨어요."},{"n":16,"t":"아내여, 당신이 남편을 구원할 수 있을지 어떻게 알겠어요? 또 남편이여, 당신이 아내를 구원할 수 있을지 어떻게 알겠어요?"},{"n":17,"t":"다만 주님께서 각 사람에게 나누어 주신 그대로, 또 하나님께서 부르신 그 자리에서 그대로 살아가세요. 나는 모든 교회에서 이렇게 가르쳐요."},{"n":18,"t":"할례(유대인의 종교적 표시인 몸의 표)를 받은 채로 부르심을 받았나요? 그것을 없애려고 하지 마세요. 할례를 받지 않은 채로 부르심을 받았나요? 굳이 할례를 받으려고 하지 마세요."},{"n":19,"t":"할례를 받았느냐 받지 않았느냐는 중요하지 않아요. 중요한 것은 하나님의 계명을 지키는 거예요."},{"n":20,"t":"각자 부르심을 받았을 때 그대로의 자리에서 그대로 지내세요."},{"n":21,"t":"종이었을 때 부르심을 받았나요? 걱정하지 마세요. 그러나 자유롭게 될 기회가 있거든 그 기회를 잡으세요."},{"n":22,"t":"주님 안에서 부르심을 받은 사람은 종이라도 주님께 속한 자유인이고, 마찬가지로 자유인일 때 부르심을 받은 사람은 그리스도의 종이에요."},{"n":23,"t":"여러분은 값을 치르고 산 사람들이니, 사람의 종이 되지 마세요."},{"n":24,"t":"형제 여러분, 각자 부르심을 받았을 때 그 자리에서 하나님과 함께 지내세요."},{"n":25,"t":"결혼하지 않은 처녀들에 대해서는 주님께 받은 직접적인 명령이 없어요. 다만 주님의 자비를 받아 신실한 사람이 된 사람으로서 내 의견을 말해 줄게요."},{"n":26,"t":"내 생각에는, 지금 닥친 어려운 시대 때문에 사람이 결혼하지 않고 그대로 지내는 것이 좋아요."},{"n":27,"t":"이미 아내와 결혼해 있나요? 그러면 헤어지려고 하지 마세요. 아내에게서 풀려나 혼자인가요? 그러면 굳이 결혼할 사람을 찾지 마세요."},{"n":28,"t":"그러나 결혼해도 죄가 아니고, 처녀가 시집가도 죄가 아니에요. 다만 결혼한 사람들은 살면서 어려움을 겪게 될 텐데, 나는 여러분이 그런 어려움을 덜 겪었으면 해요."},{"n":29,"t":"형제 여러분, 내가 이 말을 하는 것은, 정해진 때가 얼마 남지 않았기 때문이에요. 이제부터는 아내 있는 사람도 마치 아내가 없는 사람처럼,"},{"n":30,"t":"우는 사람도 울지 않는 사람처럼, 기뻐하는 사람도 기뻐하지 않는 사람처럼, 사고파는 사람도 자기 것이 따로 없는 사람처럼,"},{"n":31,"t":"세상의 물건을 쓰는 사람도 그것에 빠지지 않은 사람처럼 살아가세요. 이 세상의 모습은 곧 지나가 버릴 것이기 때문이에요."},{"n":32,"t":"나는 여러분이 걱정 없이 살았으면 해요. 결혼하지 않은 사람은 어떻게 하면 주님을 기쁘시게 할까 하면서 주님의 일에만 마음을 쓸 수 있어요."},{"n":33,"t":"그러나 결혼한 사람은 어떻게 하면 아내를 기쁘게 할까 하면서 세상일에 마음을 쓰게 되어 마음이 둘로 나뉘어요."},{"n":34,"t":"결혼하지 않은 여자와 처녀는 몸과 영을 다 거룩하게 하려고 주님의 일에 마음을 쓰지만, 결혼한 여자는 어떻게 하면 남편을 기쁘게 할까 하면서 세상일에 마음을 쓰게 돼요."},{"n":35,"t":"내가 이 말을 하는 것은 여러분에게 유익이 되라는 것이지, 여러분을 구속하려는 게 아니에요. 여러분이 흐트러짐 없이 단정하게 주님을 섬기도록 하려는 거예요."},{"n":36,"t":"그런데 누가 자기 처녀 딸(또는 약혼한 처녀)을 대하는 것이 옳지 않다고 생각하고, 또 그 딸의 결혼할 나이가 지나서 결혼이 필요한 상황이라면, 마음대로 하세요. 그것은 죄가 아니에요. 결혼시키세요."},{"n":37,"t":"그러나 마음을 굳게 정하고 어쩔 수 없는 사정도 없으며, 자기 뜻대로 할 수 있는 권리가 있어서 자기 처녀 딸을 결혼시키지 않기로 결심한 사람도 잘하는 것이에요."},{"n":38,"t":"그러므로 처녀 딸을 결혼시키는 사람도 잘하는 것이고, 결혼시키지 않는 사람은 더 잘하는 것이에요."},{"n":39,"t":"아내는 남편이 살아 있는 동안 남편에게 매여 있어요. 남편이 죽으면 자기 뜻대로 결혼할 수 있게 자유롭지만, 다만 주님 안에 있는 사람과만 결혼해야 해요."},{"n":40,"t":"그러나 내 의견으로는 그대로 혼자 지내는 게 더 복이 있어요. 나도 하나님의 영(성령)을 받았다고 생각해요."}]}},{"chapter":8,"title":"우상 제물 문제","verses":{"krv":[{"n":1,"t":"우상의 제물에 대하여는 우리가 다 지식이 있는 줄을 아나 지식은 교만하게 하며 사랑은 덕을 세우나니"},{"n":2,"t":"만일 누구든지 무엇을 아는 줄로 생각하면 아직도 마땅히 알 것을 알지 못하는 것이요"},{"n":3,"t":"또 누구든지 하나님을 사랑하면 이 사람은 하나님의 아시는 바 되었느니라"},{"n":4,"t":"그러므로 우상의 제물 먹는 일에 대하여는 우리가 우상은 세상에 아무 것도 아니며 또한 하나님은 한 분밖에 없는 줄 아노라"},{"n":5,"t":"비록 하늘에나 땅에나 신이라 칭하는 자가 있어 많은 신과 많은 주가 있으나"},{"n":6,"t":"그러나 우리에게는 한 하나님 곧 아버지가 계시니 만물이 그에게서 났고 우리도 그를 위하여 또한 한 주 예수 그리스도께서 계시니 만물이 그로 말미암고 우리도 그로 말미암았느니라"},{"n":7,"t":"그러나 이 지식은 사람마다 가지지 못하여 어떤 이들은 지금까지 우상에 대한 습관이 있어 우상의 제물로 알고 먹는 고로 그들의 양심이 악하여지고 더러워지느니라"},{"n":8,"t":"식물은 우리를 하나님 앞에 세우지 못하나니 우리가 먹지 아니하여도 부족함이 없고 먹어도 풍족함이 없으리라"},{"n":9,"t":"그런즉 너희 자유함이 약한 자들에게 거치는 것이 되지 않도록 조심하라"},{"n":10,"t":"지식 있는 네가 우상의 집에 앉아 먹는 것을 누구든지 보면 그 약한 자들의 양심이 담력을 얻어 어찌 우상의 제물을 먹게 되지 않겠느냐"},{"n":11,"t":"그러면 네 지식으로 그 약한 자가 멸망하나니 그는 그리스도께서 위하여 죽으신 형제라"},{"n":12,"t":"이같이 너희가 형제에게 죄를 지어 그 약한 양심을 상하게 하는 것이 곧 그리스도에게 지를 짓는 것이니라"},{"n":13,"t":"그러므로 만일 식물이 내 형제로 실족케 하면 나는 영원히 고기를 먹지 아니하여 내 형제를 실족치 않게 하리라"}],"kids":[{"n":1,"t":"우상에게 바쳤던 제물(고기)에 대해서는, 우리 모두가 어느 정도 지식을 가지고 있다는 것을 알아요. 그러나 지식은 사람을 우쭐하게 만들고, 사랑은 사람을 든든하게 세워 줘요."},{"n":2,"t":"누가 무엇을 안다고 생각한다면, 그 사람은 사실 마땅히 알아야 할 것을 아직 제대로 알지 못하는 거예요."},{"n":3,"t":"그러나 누구든지 하나님을 사랑하면, 그 사람은 하나님께서 알아주시는(인정해 주시는) 사람이에요."},{"n":4,"t":"그러므로 우상에게 바쳤던 제물을 먹는 일에 대해 말하자면, 우리는 세상에 우상이라는 것은 사실 아무것도 아니라는 것과, 하나님은 오직 한 분뿐이시라는 것을 알아요."},{"n":5,"t":"비록 하늘이나 땅에 신이라고 부르는 것들이 있어서 \\"많은 신과 많은 주\\"가 있다고들 하지만,"},{"n":6,"t":"우리에게는 오직 한 분 하나님, 곧 아버지께서 계세요. 만물이 그분에게서 나왔고, 우리도 그분을 위해 살아요. 또 오직 한 분 주님이신 예수 그리스도께서 계세요. 만물이 그분을 통해 지어졌고, 우리도 그분을 통해 살고 있어요."},{"n":7,"t":"그러나 모든 사람이 이런 지식을 가지고 있는 건 아니에요. 어떤 사람들은 지금도 우상을 섬기던 옛 습관이 남아 있어서, 고기를 먹을 때에도 그것을 우상의 제물이라고 여기며 먹어요. 그래서 그들의 약한 양심이 더러워지고 흐려져요."},{"n":8,"t":"음식이 우리를 하나님 앞에 더 세워 주는 것은 아니에요. 먹지 않는다고 손해 볼 것도 없고, 먹는다고 더 나아질 것도 없어요."},{"n":9,"t":"그러나 여러분의 자유가 믿음이 약한 사람들에게 걸려 넘어지게 하는 일이 되지 않도록 조심하세요."},{"n":10,"t":"지식이 있는 당신이 우상의 신전에 앉아 음식을 먹고 있는 모습을 누가 본다면, 양심이 약한 그 사람도 용기를 얻어 우상에게 바친 제물을 먹게 되지 않겠어요?"},{"n":11,"t":"그러면 당신의 지식 때문에, 그리스도께서 그 사람을 위해 죽기까지 하신 그 약한 형제가 망하게 되는 거예요."},{"n":12,"t":"이렇게 여러분이 형제에게 죄를 짓고, 그들의 약한 양심을 상하게 하는 것은 곧 그리스도께 죄를 짓는 거예요."},{"n":13,"t":"그러므로 음식이 내 형제를 걸려 넘어지게 한다면, 나는 형제를 넘어지지 않게 하기 위해 평생 고기를 먹지 않을 거예요."}]}},{"chapter":9,"title":"사도 바울의 자유","verses":{"krv":[{"n":1,"t":"내가 자유자가 아니냐 사도가 아니냐 예수 우리 주를 보지 못하였느냐 주 안에서 행한 나의 일이 너희가 아니냐"},{"n":2,"t":"다른 사람들에게는 내가 사도가 아닐지라도 너희에게는 사도니 나의 사도 됨을 주 안에서 인친 것이 너희라"},{"n":3,"t":"나를 힐문하는 자들에게 발명할 것이 이것이니"},{"n":4,"t":"우리가 먹고 마시는 권이 없겠느냐"},{"n":5,"t":"우리가 다른 사도들과 주의 형제들과 게바와 같이 자매 된 아내를 데리고 다닐 권이 없겠느냐"},{"n":6,"t":"어찌 나와 바나바만 일하지 아니할 권이 없겠느냐"},{"n":7,"t":"누가 자비량하고 병정을 다니겠느냐 누가 포도를 심고 그 실과를 먹지 않겠느냐 누가 양떼를 기르고 그 양떼의 젖을 먹지 않겠느냐"},{"n":8,"t":"내가 사람의 예대로 이것을 말하느냐 율법도 이것을 말하지 아니하느냐"},{"n":9,"t":"모세 율법에 곡식을 밟아 떠는 소에게 망을 씌우지 말라 기록하였으니 하나님께서 어찌 소들을 위하여 염려하심이냐"},{"n":10,"t":"전혀 우리를 위하여 말씀하심이 아니냐 과연 우리를 위하여 기록된 것이니 밭 가는 자는 소망을 가지고 갈며 곡식 떠는 자는 함께 얻을 소망을 가지고 떠는 것이라"},{"n":11,"t":"우리가 너희에게 신령한 것을 뿌렸은즉 너희 육신의 것을 거두기로 과하다 하겠느냐"},{"n":12,"t":"다른 이들도 너희에게 이런 권을 가졌거든 하물며 우리일까보냐 그러나 우리가 이 권을 쓰지 아니하고 범사에 참는 것은 그리스도의 복음에 아무 장애가 없게 하려 함이로다"},{"n":13,"t":"성전의 일을 하는 이들은 성전에서 나는 것을 먹으며 제단을 모시는 이들은 제단과 함께 나누는 것을 너희가 알지 못하느냐"},{"n":14,"t":"이와 같이 주께서도 복음 전하는 자들이 복음으로 말미암아 살리라 명하셨느니라"},{"n":15,"t":"그러나 내가 이것을 하나도 쓰지 아니하였고 또 이 말을 쓰는 것은 내게 이같이 하여 달라는 것이 아니라 내가 차라리 죽을지언정 누구든지 내 자랑하는 것을 헛된 데로 돌리지 못하게 하리라"},{"n":16,"t":"내가 복음을 전할지라도 자랑할 것이 없음은 내가 부득불 할 일임이라 만일 복음을 전하지 아니하면 내게 화가 있을 것임이로라"},{"n":17,"t":"내가 내 임의로 이것을 행하면 상을 얻으려니와 임의로 아니한다 할지라도 나는 직분을 맡았노라"},{"n":18,"t":"그런즉 내 상이 무엇이냐 내가 복음을 전할 때에 값없이 전하고 복음으로 인하여 내게 있는 권을 다 쓰지 아니하는 이것이로라"},{"n":19,"t":"내가 모든 사람에게 자유하였으나 스스로 모든 사람에게 종이 된 것은 더 많은 사람을 얻고자 함이라"},{"n":20,"t":"유대인들에게는 내가 유대인과 같이 된 것은 유대인들을 얻고자 함이요 율법 아래 있는 자들에게는 내가 율법 아래 있지 아니하나 율법 아래 있는 자 같이 된 것은 율법 아래 있는 자들을 얻고자 함이요"},{"n":21,"t":"율법 없는 자에게는 내가 하나님께는 율법 없는 자가 아니요 도리어 그리스도의 율법 아래 있는 자나 율법 없는 자와 같이 된 것은 율법 없는 자들을 얻고자 함이라"},{"n":22,"t":"약한 자들에게는 내가 약한 자와 같이 된 것은 약한 자들을 얻고자 함이요 여러 사람에게 내가 여러 모양이 된 것은 아무쪼록 몇몇 사람들을 구원코자 함이니"},{"n":23,"t":"내가 복음을 위하여 모든 것을 행함은 복음에 참예하고자 함이라"},{"n":24,"t":"운동장에서 달음질하는 자들이 다 달아날지라도 오직 상 얻는 자는 하나인 줄을 너희가 알지 못하느냐 너희도 얻도록 이와 같이 달음질하라"},{"n":25,"t":"이기기를 다투는 자마다 모든 일에 절제하나니 저희는 썩을 면류관을 얻고자 하되 우리는 썩지 아니할 것을 얻고자 하노라"},{"n":26,"t":"그러므로 내가 달음질하기를 향방 없는 것 같이 아니하고 싸우기를 허공을 치는 것 같이 아니하여"},{"n":27,"t":"내가 내 몸을 쳐 복종하게 함은 내가 남에게 전파한 후에 자기가 도리어 버림이 될까 두려워함이로라"}],"kids":[]}},{"chapter":10,"title":"광야 이스라엘의 본보기","verses":{"krv":[{"n":1,"t":"형제들아 너희가 알지 못하기를 내가 원치 아니하노니 우리 조상들이 다 구름 아래 있고 바다 가운데로 지나며"},{"n":2,"t":"모세에게 속하여 다 구름과 바다에서 침례를 받고"},{"n":3,"t":"다 같은 신령한 식물을 먹으며"},{"n":4,"t":"다 같은 신령한 음료를 마셨으니 이는 저희를 따르는 신령한 반석으로부터 마셨으매 그 반석은 곧 그리스도시라"},{"n":5,"t":"그러나 저희의 다수를 하나님이 기뻐하지 아니하신 고로 저희가 광야에서 멸망을 받았느니라"},{"n":6,"t":"그런 일은 우리의 거울이 되어 우리로 하여금 저희가 악을 즐겨한 것 같이 즐겨하는 자가 되지 않게 하려 함이니"},{"n":7,"t":"저희 중에 어떤 이들과 같이 너희는 우상 숭배하는 자가 되지 말라 기록된 바 백성이 앉아서 먹고 마시며 일어나서 뛰논다 함과 같으니라"},{"n":8,"t":"저희 중에 어떤 이들이 간음하다가 하루에 이만 삼천 명이 죽었나니 우리는 저희와 같이 간음하지 말자"},{"n":9,"t":"저희 중에 어떤 이들이 주를 시험하다가 뱀에게 멸망하였나니 우리는 저희와 같이 시험하지 말자"},{"n":10,"t":"저희 중에 어떤 이들이 원망하다가 멸망시키는 자에게 멸망하였나니 너희는 저희와 같이 원망하지 말라"},{"n":11,"t":"저희에게 당한 이런 일이 거울이 되고 또한 말세를 만난 우리의 경계로 기록하였느니라"},{"n":12,"t":"그런즉 선 줄로 생각하는 자는 넘어질까 조심하라"},{"n":13,"t":"사람이 감당할 시험 밖에는 너희에게 당한 것이 없나니 오직 하나님은 미쁘사 너희가 감당치 못할 시험 당함을 허락지 아니하시고 시험 당할 즈음에 또한 피할 길을 내사 너희로 능히 감당하게 하시느니라"},{"n":14,"t":"그런즉 내 사랑하는 자들아 우상 숭배하는 일을 피하라"},{"n":15,"t":"나는 지혜있는 자들에게 말함과 같이 하노니 너희는 내 이르는 말을 스스로 판단하라"},{"n":16,"t":"우리가 축복하는 바 축복의 잔은 그리스도의 피에 참예함이 아니며 우리가 떼는 떡은 그리스도의 몸에 참예함이 아니냐"},{"n":17,"t":"떡이 하나요 많은 우리가 한 몸이니 이는 우리가 다 한 떡에 참예함이라"},{"n":18,"t":"육신을 따라 난 이스라엘을 보라 제물을 먹는 자들이 제단에 참예하는 자들이 아니냐"},{"n":19,"t":"그런즉 내가 무엇을 말하느뇨 우상의 제물은 무엇이며 우상은 무엇이라 하느뇨"},{"n":20,"t":"대저 이방인의 제사하는 것은 귀신에게 하는 것이요 하나님께 제사하는 것이 아니니 나는 너희가 귀신과 교제하는 자 되기를 원치 아니하노라"},{"n":21,"t":"너희가 주의 잔과 귀신의 잔을 겸하여 마시지 못하고 주의 상과 귀신의 상에 겸하여 참예치 못하리라"},{"n":22,"t":"그러면 우리가 주를 노여워하시게 하겠느냐 우리가 주보다 강한 자냐"},{"n":23,"t":"모든 것이 가하나 모든 것이 유익한 것이 아니요 모든 것이 가하나 모든 것이 덕을 세우는 것이 아니니"},{"n":24,"t":"누구든지 자기의 유익을 구치 말고 남의 유익을 구하라"},{"n":25,"t":"무릇 시장에서 파는 것은 양심을 위하여 묻지 말고 먹으라"},{"n":26,"t":"이는 땅과 거기 충만한 것이 주의 것임이니라"},{"n":27,"t":"불신자 중 누가 너희를 청하매 너희가 가고자 하거든 너희 앞에 무엇이든지 차려 놓은 것은 양심을 위하여 묻지 말고 먹으라"},{"n":28,"t":"누가 너희에게 이것이 제물이라 말하거든 알게 한 자와 및 양심을 위하여 먹지 말라"},{"n":29,"t":"내가 말한 양심은 너희의 것이 아니요 남의 것이니 어찌하여 내 자유가 남의 양심으로 말미암아 판단을 받으리요"},{"n":30,"t":"만일 내가 감사함으로 참예하면 어찌하여 내가 감사하다 하는 것에 대하여 비방을 받으리요"},{"n":31,"t":"그런즉 너희가 먹든지 마시든지 무엇을 하든지 다 하나님의 영광을 위하여 하라"},{"n":32,"t":"유대인에게나 헬라인에게나 하나님의 교회에나 거치는 자가 되지 말고"},{"n":33,"t":"나와 같이 모든 일에 모든 사람을 기쁘게 하여 나의 유익을 구치 아니하고 많은 사람의 유익을 구하여 저희로 구원을 얻게 하라"}],"kids":[]}},{"chapter":11,"title":"예배와 성찬","verses":{"krv":[{"n":1,"t":"내가 그리스도를 본받는 자 된 것 같이 너희는 나를 본받는 자 되라"},{"n":2,"t":"너희가 모든 일에 나를 기억하고 또 내가 너희에게 전하여 준 대로 그 유전을 너희가 지키므로 너희를 칭찬하노라"},{"n":3,"t":"그러나 나는 너희가 알기를 원하노니 각 남자의 머리는 그리스도요 여자의 머리는 남자요 그리스도의 머리는 하나님이시라"},{"n":4,"t":"무릇 남자로서 머리에 무엇을 쓰고 기도나 예언을 하는 자는 그 머리를 욕되게 하는 것이요"},{"n":5,"t":"무릇 여자로서 머리에 쓴 것을 벗고 기도나 예언을 하는 자는 그 머리를 욕되게 하는 것이니 이는 머리 민 것과 다름이 없음이니라"},{"n":6,"t":"만일 여자가 머리에 쓰지 않거든 깎을 것이요 만일 깎거나 미는 것이 여자에게 부끄러움이 되거든 쓸지니라"},{"n":7,"t":"남자는 하나님의 형상과 영광이니 그 머리에 마땅히 쓰지 않거니와 여자는 남자의 영광이니라"},{"n":8,"t":"남자가 여자에게서 난 것이 아니요 여자가 남자에게서 났으며"},{"n":9,"t":"또 남자가 여자를 위하여 지음을 받지 아니하고 여자가 남자를 위하여 지음을 받은 것이니"},{"n":10,"t":"이러므로 여자는 천사들을 인하여 권세 아래 있는 표를 그 머리 위에 둘지니라"},{"n":11,"t":"그러나 주 안에는 남자 없이 여자만 있지 않고 여자 없이 남자만 있지 아니하니라"},{"n":12,"t":"여자가 남자에게서 난 것 같이 남자도 여자로 말미암아 났으나 모든 것이 하나님에게서 났느니라"},{"n":13,"t":"너희는 스스로 판단하라 여자가 쓰지 않고 하나님께 기도하는 것이 마땅하냐"},{"n":14,"t":"만일 남자가 긴 머리가 있으면 자기에게 욕되는 것을 본성이 너희에게 가르치지 아니하느냐"},{"n":15,"t":"만일 여자가 긴 머리가 있으면 자기에게 영광이 되나니 긴 머리는 쓰는 것을 대신하여 주신 연고니라"},{"n":16,"t":"변론하려는 태도를 가진 자가 있을지라도 우리에게나 하나님의 모든 교회에는 이런 규례가 없느니라"},{"n":17,"t":"내가 명하는 이 일에 너희를 칭찬하지 아니하나니 이는 저희의 모임이 유익이 못되고 도리어 해로움이라"},{"n":18,"t":"첫째는 너희가 교회에 모일 때에 너희 중에 분쟁이 있다 함을 듣고 대강 믿노니"},{"n":19,"t":"너희 중에 편당이 있어야 너희 중에 옳다 인정함을 받은 자들이 나타나게 되리라"},{"n":20,"t":"그런즉 너희가 함께 모여서 주의 만찬을 먹을 수 없으니"},{"n":21,"t":"이는 먹을 때에 각각 자기의 만찬을 먼저 갖다 먹으므로 어떤 이는 시장하고 어떤 이는 취함이라"},{"n":22,"t":"너희가 먹고 마실 집이 없느냐 너희가 하나님의 교회를 업신여기고 빈궁한 자들을 부끄럽게 하느냐 내가 너희에게 무슨 말을 하랴 너희를 칭찬하랴 이것으로 칭찬하지 않노라"},{"n":23,"t":"내가 너희에게 전한 것은 주께 받은 것이니 곧 주 예수께서 잡히시던 밤에 떡을 가지사"},{"n":24,"t":"축사하시고 떼어 가라사대 이것은 너희를 위하는 내 몸이니 이것을 행하여 나를 기념하라 하시고"},{"n":25,"t":"식후에 또한 이와 같이 잔을 가지시고 가라사대 이 잔은 내 피로 세운 새 언약이니 이것을 행하여 마실 때마다 나를 기념하라 하셨으니"},{"n":26,"t":"너희가 이 떡을 먹으며 이 잔을 마실 때마다 주의 죽으심을 오실 때까지 전하는 것이니라"},{"n":27,"t":"그러므로 누구든지 주의 떡이나 잔을 합당치 않게 먹고 마시는 자는 주의 몸과 피를 범하는 죄가 있느니라"},{"n":28,"t":"사람이 자기를 살피고 그 후에야 이 떡을 먹고 이 잔을 마실지니"},{"n":29,"t":"주의 몸을 분변치 못하고 먹고 마시는 자는 자기의 죄를 먹고 마시는 것이니라"},{"n":30,"t":"이러므로 너희 중에 약한 자와 병든 자가 많고 잠자는 자도 적지 아니하니"},{"n":31,"t":"우리가 우리를 살폈으면 판단을 받지 아니하려니와"},{"n":32,"t":"우리가 판단을 받는 것은 주께 징계를 받는 것이니 이는 우리로 세상과 함께 죄 정함을 받지 않게 하려 하심이라"},{"n":33,"t":"그런즉 내 형제들아 먹으러 모일 때에 서로 기다리라"},{"n":34,"t":"만일 누구든지 시장하거든 집에서 먹을지니 이는 너희의 판단 받는 모임이 되지 않게 하려 함이라 그 남은 것은 내가 언제든지 갈 때에 귀정하리라"}],"kids":[]}},{"chapter":12,"title":"성령의 은사와 한 몸","verses":{"krv":[{"n":1,"t":"형제들아 신령한 것에 대하여는 내가 너희의 알지 못하기를 원치 아니하노니"},{"n":2,"t":"너희도 알거니와 너희가 이방인으로 있을 때에 말 못하는 우상에게로 끄는 그대로 끌려 갔느니라"},{"n":3,"t":"그러므로 내가 너희에게 알게 하노니 하나님의 영으로 말하는 자는 누구든지 예수를 저주할 자라 하지 않고 또 성령으로 아니하고는 누구든지 예수를 주시라 할 수 없느니라"},{"n":4,"t":"은사는 여러 가지나 성령은 같고"},{"n":5,"t":"직임은 여러 가지나 주는 같으며"},{"n":6,"t":"또 역사는 여러 가지나 모든 것을 모든 사람 가운데서 역사하시는 하나님은 같으니"},{"n":7,"t":"각 사람에게 성령의 나타남을 주심은 유익하게 하려 하심이라"},{"n":8,"t":"어떤 이에게는 성령으로 말미암아 지혜의 말씀을, 어떤 이에게는 같은 성령을 따라 지식의 말씀을,"},{"n":9,"t":"다른 이에게는 같은 성령으로 믿음을, 어떤 이에게는 한 성령으로 병 고치는 은사를,"},{"n":10,"t":"어떤 이에게는 능력 행함을, 어떤 이에게는 예언함을, 어떤 이에게는 영들 분별함을, 다른 이에게는 각종 방언 말함을, 어떤 이에게는 방언들 통역함을 주시나니"},{"n":11,"t":"이 모든 일은 같은 한 성령이 행하사 그 뜻대로 각 사람에게 나눠 주시느니라"},{"n":12,"t":"몸은 하나인데 많은 지체가 있고 몸의 지체가 많으나 한 몸임과 같이 그리스도도 그러하니라"},{"n":13,"t":"우리가 유대인이나 헬라인이나 종이나 자유자나 다 한 성령으로 침례를 받아 한 몸이 되었고 또 다 한 성령을 마시게 하셨느니라"},{"n":14,"t":"몸은 한 지체뿐 아니요 여럿이니"},{"n":15,"t":"만일 발이 이르되 나는 손이 아니니 몸에 붙지 아니하였다 할지라도 이로 인하여 몸에 붙지 아니한 것이 아니요"},{"n":16,"t":"또 귀가 이르되 나는 눈이 아니니 몸에 붙지 아니하였다 할지라도 이로 인하여 몸에 붙지 아니한 것이 아니니"},{"n":17,"t":"만일 온 몸이 눈이면 듣는 곳은 어디며 온 몸이 듣는 곳이면 냄새 맡는 곳은 어디뇨"},{"n":18,"t":"그러나 이제 하나님이 그 원하시는 대로 지체를 각각 몸에 두셨으니"},{"n":19,"t":"만일 다 한 지체뿐이면 몸은 어디뇨"},{"n":20,"t":"이제 지체는 많으나 몸은 하나라"},{"n":21,"t":"눈이 손더러 내가 너를 쓸 데 없다 하거나 또한 머리가 발더러 내가 너를 쓸 데 없다 하거나 하지 못하리라"},{"n":22,"t":"이뿐 아니라 몸의 더 약하게 보이는 지체가 도리어 요긴하고"},{"n":23,"t":"우리가 몸의 덜 귀히 여기는 그것들을 더욱 귀한 것들로 입혀 주며 우리의 아름답지 못한 지체는 더욱 아름다운 것을 얻고"},{"n":24,"t":"우리의 아름다운 지체는 요구할 것이 없으니 오직 하나님이 몸을 고르게 하여 부족한 지체에게 존귀를 더하사"},{"n":25,"t":"몸 가운데서 분쟁이 없고 오직 여러 지체가 서로 같이하여 돌아보게 하셨으니"},{"n":26,"t":"만일 한 지체가 고통을 받으면 모든 지체도 함께 고통을 받고 한 지체가 영광을 얻으면 모든 지체도 함께 즐거워하나니"},{"n":27,"t":"너희는 그리스도의 몸이요 지체의 각 부분이라"},{"n":28,"t":"하나님이 교회 중에 몇을 세우셨으니 첫째는 사도요 둘째는 선지자요 셋째는 교사요 그 다음은 능력이요 그 다음은 병 고치는 은사와 서로 돕는 것과 다스리는 것과 각종 방언을 하는 것이라"},{"n":29,"t":"다 사도겠느냐 다 선지자겠느냐 다 교사겠느냐 다 능력을 행하는 자겠느냐"},{"n":30,"t":"다 병 고치는 은사를 가진 자겠느냐 다 방언을 말하는 자겠느냐 다 통역하는 자겠느냐"},{"n":31,"t":"너희는 더욱 큰 은사를 사모하라 내가 또한 제일 좋은 길을 너희에게 보이리라"}],"kids":[]}},{"chapter":13,"title":"사랑이 가장 큰 것","verses":{"krv":[{"n":1,"t":"내가 사람의 방언과 천사의 말을 할지라도 사랑이 없으면 소리나는 구리와 울리는 꽹과리가 되고"},{"n":2,"t":"내가 예언하는 능이 있어 모든 비밀과 모든 지식을 알고 또 산을 옮길 만한 모든 믿음이 있을지라도 사랑이 없으면 내가 아무 것도 아니요"},{"n":3,"t":"내가 내게 있는 모든 것으로 구제하고 또 내 몸을 불사르게 내어 줄지라도 사랑이 없으면 내게 아무 유익이 없느니라"},{"n":4,"t":"사랑은 오래 참고 사랑은 온유하며 투기하는 자가 되지 아니하며 사랑은 자랑하지 아니하며 교만하지 아니하며"},{"n":5,"t":"무례히 행치 아니하며 자기의 유익을 구치 아니하며 성내지 아니하며 악한 것을 생각지 아니하며"},{"n":6,"t":"불의를 기뻐하지 아니하며 진리와 함께 기뻐하고"},{"n":7,"t":"모든 것을 참으며 모든 것을 믿으며 모든 것을 바라며 모든 것을 견디느니라"},{"n":8,"t":"사랑은 언제까지든지 떨어지지 아니하나 예언도 폐하고 방언도 그치고 지식도 폐하리라"},{"n":9,"t":"우리가 부분적으로 알고 부분적으로 예언하니"},{"n":10,"t":"온전한 것이 올 때에는 부분적으로 하던 것이 폐하리라"},{"n":11,"t":"내가 어렸을 때에는 말하는 것이 어린 아이와 같고 깨닫는 것이 어린 아이와 같고 생각하는 것이 어린 아이와 같다가 장성한 사람이 되어서는 어린 아이의 일을 버렸노라"},{"n":12,"t":"우리가 이제는 거울로 보는 것 같이 희미하나 그 때에는 얼굴과 얼굴을 대하여 볼 것이요 이제는 내가 부분적으로 아나 그 때에는 주께서 나를 아신 것 같이 내가 온전히 알리라"},{"n":13,"t":"그런즉 믿음, 소망, 사랑, 이 세가지는 항상 있을 것인데 그 중에 제일은 사랑이라"}],"kids":[]}},{"chapter":14,"title":"방언과 예언","verses":{"krv":[{"n":1,"t":"사랑을 따라 구하라 신령한 것을 사모하되 특별히 예언을 하려고 하라"},{"n":2,"t":"방언을 말하는 자는 사람에게 하지 아니하고 하나님께 하나니 이는 알아 듣는 자가 없고 그 영으로 비밀을 말함이니라"},{"n":3,"t":"그러나 예언하는 자는 사람에게 말하여 덕을 세우며 권면하며 안위하는 것이요"},{"n":4,"t":"방언을 말하는 자는 자기의 덕을 세우고 예언하는 자는 교회의 덕을 세우나니"},{"n":5,"t":"나는 너희가 다 방언 말하기를 원하나 특별히 예언하기를 원하노라 방언을 말하는 자가 만일 교회의 덕을 세우기 위하여 통역하지 아니하면 예언하는 자만 못하니라"},{"n":6,"t":"그런즉 형제들아 내가 너희에게 나아가서 방언을 말하고 계시나 지식이나 예언이나 가르치는 것이나 말하지 아니하면 너희에게 무엇이 유익하리요"},{"n":7,"t":"혹 저나 거문고와 같이 생명 없는 것이 소리를 낼 때에 그 음의 분별을 내지 아니하면 저 부는 것인지 거문고 타는 것인지 어찌 알게 되리요"},{"n":8,"t":"만일 나팔이 분명치 못한 소리를 내면 누가 전쟁을 예비하리요"},{"n":9,"t":"이와 같이 너희도 혀로서 알아 듣기 쉬운 말을 하지 아니하면 그 말하는 것을 어찌 알리요 이는 허공에다 말하는 것이라"},{"n":10,"t":"세상에 소리의 종류가 이같이 많되 뜻 없는 소리는 없나니"},{"n":11,"t":"그러므로 내가 그 소리의 뜻을 알지 못하면 내가 말하는 자에게 야만이 되고 말하는 자도 내게 야만이 되리니"},{"n":12,"t":"그러면 너희도 신령한 것을 사모하는 자인즉 교회의 덕 세우기를 위하여 풍성하기를 구하라"},{"n":13,"t":"그러므로 방언을 말하는 자는 통역하기를 기도할지니"},{"n":14,"t":"내가 만일 방언으로 기도하면 나의 영이 기도하거니와 나의 마음은 열매를 맺히지 못하리라"},{"n":15,"t":"그러면 어떻게 할꼬 내가 영으로 기도하고 또 마음으로 기도하며 내가 영으로 찬미하고 또 마음으로 찬미하리라"},{"n":16,"t":"그렇지 아니하면 네가 영으로 축복할 때에 무식한 처지에 있는 자가 네가 무슨 말을 하는지 알지 못하고 네 감사에 어찌 아멘 하리요"},{"n":17,"t":"너는 감사를 잘하였으나 그러나 다른 사람은 덕 세움을 받지 못하리라"},{"n":18,"t":"내가 너희 모든 사람보다 방언을 더 말하므로 하나님께 감사하노라"},{"n":19,"t":"그러나 교회에서 네가 남을 가르치기 위하여 깨달은 마음으로 다섯 마디 말을 하는 것이 일만 마디 방언으로 말하는 것보다 나으니라"},{"n":20,"t":"형제들아 지혜에는 아이가 되지 말고 악에는 어린 아이가 되라 지혜에 장성한 사람이 되라"},{"n":21,"t":"율법에 기록된 바 주께서 가라사대 내가 다른 방언하는 자와 다른 입술로 이 백성에게 말할지라도 저희가 오히려 듣지 아니하리라 하였으니"},{"n":22,"t":"그러므로 방언은 믿는 자들을 위하지 않고 믿지 아니하는 자들을 위하는 표적이나 예언은 믿지 아니하는 자들을 위하지 않고 믿는 자들을 위함이니"},{"n":23,"t":"그러므로 온 교회가 함께 모여 다 방언으로 말하면 무식한 자들이나 믿지 아니하는 자들이 들어와서 너희를 미쳤다 하지 아니하겠느냐"},{"n":24,"t":"그러나 다 예언을 하면 믿지 아니하는 자들이나 무식한 자들이 들어와서 모든 사람에게 책망을 들으며 모든 사람에게 판단을 받고"},{"n":25,"t":"그 마음의 숨은 일이 드러나게 되므로 엎드리어 하나님께 경배하며 하나님이 참으로 너희 가운데 계시다 전파하리라"},{"n":26,"t":"그런즉 형제들아 어찌할꼬 너희가 모일 때에 각각 찬송시도 있으며 가르치는 말씀도 있으며 계시도 있으며 방언도 있으며 통역함도 있나니 모든 것을 덕을 세우기 위하여 하라"},{"n":27,"t":"만일 누가 방언으로 말하거든 두 사람이나 다 불과 세 사람이 차서를 따라 하고 한 사람이 통역할 것이요"},{"n":28,"t":"만일 통역하는 자가 없거든 교회에서는 잠잠하고 자기와 및 하나님께 말할 것이요"},{"n":29,"t":"예언하는 자는 둘이나 셋이나 말하고 다른 이들은 분변할 것이요"},{"n":30,"t":"만일 곁에 앉은 다른 이에게 계시가 있거든 먼저 하던 자는 잠잠할지니라"},{"n":31,"t":"너희는 다 모든 사람으로 배우게 하고 모든 사람으로 권면을 받게 하기 위하여 하나씩 하나씩 예언할 수 있느니라"},{"n":32,"t":"예언하는 자들의 영이 예언하는 자들에게 제재를 받나니"},{"n":33,"t":"하나님은 어지러움의 하나님이 아니시요 오직 화평의 하나님이시니라"},{"n":34,"t":"모든 성도의 교회에서 함과 같이 여자는 교회에서 잠잠하라 저희의 말하는 것을 허락함이 없나니 율법에 이른 것 같이 오직 복종할 것이요"},{"n":35,"t":"만일 무엇을 배우려거든 집에서 자기 남편에게 물을지니 여자가 교회에서 말하는 것은 부끄러운 것임이라"},{"n":36,"t":"하나님의 말씀이 너희에게로부터 난 것이냐 또는 너희에게만 임한 것이냐"},{"n":37,"t":"만일 누구든지 자기를 선지자나 혹 신령한 자로 생각하거든 내가 너희에게 편지한 것이 주의 명령인 줄 알라"},{"n":38,"t":"만일 누구든지 알지 못하면 그는 알지 못한 자니라"},{"n":39,"t":"그런즉 내 형제들아 예언하기를 사모하며 방언 말하기를 금하지 말라"},{"n":40,"t":"모든 것을 적당하게 하고 질서대로 하라"}],"kids":[]}},{"chapter":15,"title":"부활의 진리","verses":{"krv":[{"n":1,"t":"형제들아 내가 너희에게 전한 복음을 너희로 알게 하노니 이는 너희가 받은 것이요 또 그 가운데 선 것이라"},{"n":2,"t":"너희가 만일 나의 전한 그 말을 굳게 지키고 헛되이 믿지 아니하였으면 이로 말미암아 구원을 얻으리라"},{"n":3,"t":"내가 받은 것을 먼저 너희에게 전하였노니 이는 성경대로 그리스도께서 우리 죄를 위하여 죽으시고"},{"n":4,"t":"장사 지낸 바 되었다가 성경대로 사흘 만에 다시 살아나사"},{"n":5,"t":"게바에게 보이시고 후에 열두 제자에게와"},{"n":6,"t":"그 후에 오백여 형제에게 일시에 보이셨나니 그 중에 지금까지 태반이나 살아 있고 어떤 이는 잠들었으며"},{"n":7,"t":"그 후에 야고보에게 보이셨으며 그 후에 모든 사도에게와"},{"n":8,"t":"맨 나중에 만삭되지 못하여 난 자 같은 내게도 보이셨느니라"},{"n":9,"t":"나는 사도 중에 지극히 작은 자라 내가 하나님의 교회를 핍박하였으므로 사도라 칭함을 받기에 감당치 못할 자로라"},{"n":10,"t":"그러나 나의 나 된 것은 하나님의 은혜로 된 것이니 내게 주신 그의 은혜가 헛되지 아니하여 내가 모든 사도보다 더 많이 수고하였으나 내가 아니요 오직 나와 함께 하신 하나님의 은혜로라"},{"n":11,"t":"그러므로 내나 저희나 이같이 전파하매 너희도 이같이 믿었느니라"},{"n":12,"t":"그리스도께서 죽은 자 가운데서 다시 살아나셨다 전파되었거늘 너희 중에서 어떤 이들은 어찌하여 죽은 자 가운데서 부활이 없다 하느냐"},{"n":13,"t":"만일 죽은 자의 부활이 없으면 그리스도도 다시 살지 못하셨으리라"},{"n":14,"t":"그리스도께서 만일 다시 살지 못하셨으면 우리의 전파하는 것도 헛것이요 또 너희 믿음도 헛것이며"},{"n":15,"t":"또 우리가 하나님의 거짓 증인으로 발견되리니 우리가 하나님이 그리스도를 다시 살리셨다고 증거하였음이라 만일 죽은 자가 다시 사는 것이 없으면 하나님이 그리스도를 다시 살리시지 아니하셨으리라"},{"n":16,"t":"만일 죽은 자가 다시 사는 것이 없으면 그리스도도 다시 사신 것이 없었을 터이요"},{"n":17,"t":"그리스도께서 다시 사신 것이 없으면 너희의 믿음도 헛되고 너희가 여전히 죄 가운데 있을 것이요"},{"n":18,"t":"또한 그리스도 안에서 잠자는 자도 망하였으리니"},{"n":19,"t":"만일 그리스도 안에서 우리의 바라는 것이 다만 이생뿐이면 모든 사람 가운데 우리가 더욱 불쌍한 자리라"},{"n":20,"t":"그러나 이제 그리스도께서 죽은 자 가운데서 다시 살아 잠자는 자들의 첫 열매가 되셨도다"},{"n":21,"t":"사망이 사람으로 말미암았으니 죽은 자의 부활도 사람으로 말미암는도다"},{"n":22,"t":"아담 안에서 모든 사람이 죽은 것 같이 그리스도 안에서 모든 사람이 삶을 얻으리라"},{"n":23,"t":"그러나 각각 자기 차례대로 되리니 먼저는 첫 열매인 그리스도요 다음에는 그리스도 강림하실 때에 그에게 붙은 자요"},{"n":24,"t":"그 후에는 나중이니 저가 모든 정사와 모든 권세와 능력을 멸하시고 나라를 아버지 하나님께 바칠 때라"},{"n":25,"t":"저가 모든 원수를 그 발 아래 둘 때까지 불가불 왕 노릇 하시리니"},{"n":26,"t":"맨 나중에 멸망 받을 원수는 사망이니라"},{"n":27,"t":"만물을 저의 발 아래 두셨다 하셨으니 만물을 아래 둔다 말씀하실 때에 만물을 저의 아래 두신 이가 그 중에 들지 아니한 것이 분명하도다"},{"n":28,"t":"만물을 저에게 복종하게 하신 때에는 아들 자신도 그 때에 만물을 자기에게 복종케 하신 이에게 복종케 되리니 이는 하나님이 만유의 주로서 만유 안에 계시려 하심이라"},{"n":29,"t":"만일 죽은 자들이 도무지 다시 살지 못하면 죽은 자들을 위하여 침례 받는 자들이 무엇을 하겠느냐 어찌하여 저희를 위하여 침례를 받느뇨"},{"n":30,"t":"또 어찌하여 우리가 때마다 위험을 무릅쓰리요"},{"n":31,"t":"형제들아 내가 그리스도 예수 우리 주 안에서 가진 바 너희에게 대한 나의 자랑을 두고 단언하노니 나는 날마다 죽노라"},{"n":32,"t":"내가 범인처럼 에베소에서 맹수로 더불어 싸웠으면 내게 무슨 유익이 있느뇨 죽은 자가 다시 살지 못할 것이면 내일 죽을 터이니 먹고 마시자 하리라"},{"n":33,"t":"속지 말라 악한 동무들은 선한 행실을 더럽히나니"},{"n":34,"t":"깨어 의를 행하고 죄를 짓지 말라 하나님을 알지 못하는 자가 있기로 내가 너희를 부끄럽게 하기 위하여 말하노라"},{"n":35,"t":"누가 묻기를 죽은 자들이 어떻게 다시 살며 어떠한 몸으로 오느냐 하리니"},{"n":36,"t":"어리석은 자여 너의 뿌리는 씨가 죽지 않으면 살아나지 못하겠고"},{"n":37,"t":"또 너의 뿌리는 것은 장래 형체를 뿌리는 것이 아니요 다만 밀이나 다른 것의 알갱이뿐이로되"},{"n":38,"t":"하나님이 그 뜻대로 저에게 형체를 주시되 각 종자에게 그 형체를 주시느니라"},{"n":39,"t":"육체는 다 같은 육체가 아니니 하나는 사람의 육체요 하나는 짐승의 육체요 하나는 새의 육체요 하나는 물고기의 육체라"},{"n":40,"t":"하늘에 속한 형체도 있고 땅에 속한 형체도 있으나 하늘에 속한 자의 영광이 따로 있고 땅에 속한 자의 영광이 따로 있으니"},{"n":41,"t":"해의 영광도 다르며 달의 영광도 다르며 별의 영광도 다른데 별과 별의 영광이 다르도다"},{"n":42,"t":"죽은 자의 부활도 이와 같으니 썩을 것으로 심고 썩지 아니할 것으로 다시 살며"},{"n":43,"t":"욕된 것으로 심고 영광스러운 것으로 다시 살며 약한 것으로 심고 강한 것으로 다시 살며"},{"n":44,"t":"육의 몸으로 심고 신령한 몸으로 다시 사나니 육의 몸이 있은즉 또 신령한 몸이 있느니라"},{"n":45,"t":"기록된 바 첫 사람 아담은 산 영이 되었다 함과 같이 마지막 아담은 살려주는 영이 되었나니"},{"n":46,"t":"그러나 먼저는 신령한 자가 아니요 육 있는 자요 그 다음에 신령한 자니라"},{"n":47,"t":"첫 사람은 땅에서 났으니 흙에 속한 자이거니와 둘째 사람은 하늘에서 나셨느니라"},{"n":48,"t":"무릇 흙에 속한 자는 저 흙에 속한 자들과 같고 무릇 하늘에 속한 자는 저 하늘에 속한 자들과 같으니"},{"n":49,"t":"우리가 흙에 속한 자의 형상을 입은 것 같이 또한 하늘에 속한 자의 형상을 입으리라"},{"n":50,"t":"형제들아 내가 이것을 말하노니 혈과 육은 하나님 나라를 유업으로 받을 수 없고 또한 썩은 것은 썩지 아니한 것을 유업으로 받지 못하느니라"},{"n":51,"t":"보라 내가 너희에게 비밀을 말하노니 우리가 다 잠잘 것이 아니요 마지막 나팔에 순식간에 홀연히 다 변화하리니"},{"n":52,"t":"나팔 소리가 나매 죽은 자들이 썩지 아니할 것으로 다시 살고 우리도 변화하리라"},{"n":53,"t":"이 썩을 것이 불가불 썩지 아니할 것을 입겠고 이 죽을 것이 죽지 아니함을 입으리로다"},{"n":54,"t":"이 썩을 것이 썩지 아니함을 입고 이 죽을 것이 죽지 아니함을 입을 때에는 사망이 이김의 삼킨 바 되리라고 기록된 말씀이 응하리라"},{"n":55,"t":"사망아 너의 이기는 것이 어디 있느냐 사망아 너의 쏘는 것이 어디 있느냐"},{"n":56,"t":"사망의 쏘는 것은 죄요 죄의 권능은 율법이라"},{"n":57,"t":"우리 주 예수 그리스도로 말미암아 우리에게 이김을 주시는 하나님께 감사하노니"},{"n":58,"t":"그러므로 내 사랑하는 형제들아 견고하며 흔들리지 말며 항상 주의 일에 더욱 힘쓰는 자들이 되라 이는 너희 수고가 주 안에서 헛되지 않은 줄을 앎이니라"}],"kids":[]}},{"chapter":16,"title":"연보와 인사","verses":{"krv":[{"n":1,"t":"성도를 위하는 연보에 대하여는 내가 갈라디아 교회들에게 명한 것 같이 너희도 그렇게 하라"},{"n":2,"t":"매주일 첫날에 너희 각 사람이 이를 얻은 대로 저축하여 두어서 내가 갈 때에 연보를 하지 않게 하라"},{"n":3,"t":"내가 이를 때에 너희의 인정한 사람에게 편지를 주어 너희의 은혜를 예루살렘으로 가지고 가게 하리니"},{"n":4,"t":"만일 나도 가는 것이 합당하면 저희가 나와 함께 가리라"},{"n":5,"t":"내가 마게도냐를 지날 터이니 마게도냐를 지난 후에 너희에게 나아가서"},{"n":6,"t":"혹 너희와 함께 머물며 과동할 듯도 하니 이는 너희가 나를 나의 갈 곳으로 보내어 주게 하려 함이라"},{"n":7,"t":"이제는 지나는 길에 너희 보기를 원치 하니하노니 이는 주께서 만일 허락하시면 얼마 동안 너희와 함께 유하기를 바람이라"},{"n":8,"t":"내가 오순절까지 에베소에 유하려 함은"},{"n":9,"t":"내게 광대하고 공효를 이루는 문이 열리고 대적하는 자가 많음이니라"},{"n":10,"t":"디모데가 이르거든 너희는 조심하여 저로 두려움이 없이 너희 가운데 있게 하라 이는 저도 나와 같이 주의 일을 힘쓰는 자임이니라"},{"n":11,"t":"그러므로 누구든지 저를 멸시하지 말고 평안히 보내어 내게로 오게 하라 나는 저가 형제들과 함께 오기를 기다리노라"},{"n":12,"t":"형제 아볼로에 대하여는 저더러 형제들과 함께 너희에게 가라고 내가 많이 권하되 지금은 갈 뜻이 일절 없으나 기회가 있으면 가리라"},{"n":13,"t":"깨어 믿음에 굳게 서서 남자답게 강건하여라"},{"n":14,"t":"너희 모든 일을 사랑으로 행하라"},{"n":15,"t":"형제들아 스데바나의 집은 곧 아가야의 첫 열매요 또 성도 섬기기로 작정한 줄을 너희가 아는지라 내가 너희를 권하노니"},{"n":16,"t":"이 같은 자들과 또 함께 일하며 수고하는 모든 자에게 복종하라"},{"n":17,"t":"내가 스데바나와 브드나도와 아가이고의 온 것을 기뻐하노니 저희가 너희의 부족한 것을 보충하였음이니라"},{"n":18,"t":"저희가 나와 너희 마음을 시원케 하였으니 그러므로 너희는 이런 자들을 알아 주라"},{"n":19,"t":"아시아의 교회들이 너희에게 문안하고 아굴라와 브리스가와 및 그 집에 있는 교회가 주 안에서 너희에게 간절히 문안하고"},{"n":20,"t":"모든 형제도 너희에게 문안하니 너희는 거룩하게 입맞춤으로 서로 문안하라"},{"n":21,"t":"나 바울은 친필로 너희에게 문안하노니"},{"n":22,"t":"만일 누구든지 주를 사랑하지 아니하거든 저주를 받을지어다 주께서 임하시느니라"},{"n":23,"t":"주 예수 그리스도의 은혜가 너희와 함께 하고"},{"n":24,"t":"나의 사랑이 그리스도 예수의 안에서 너희 무리와 함께 할지어다"}],"kids":[]}}]}');

